import './pair-components/button';

import './components/admin/admin_dashboard';
import './components/experiment_builder/experiment_builder';
import './components/experiment_dashboard/experiment_dashboard';
import './components/gallery/home_gallery';
import './components/header/header';
import './components/login/login';
import './components/participant_view/cohort_landing';
import './components/participant_view/participant_view';
import './components/settings/settings';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing, TemplateResult} from 'lit';
import {customElement} from 'lit/decorators.js';
import {classMap} from 'lit/directives/class-map.js';

import {core} from './core/core';
import {AnalyticsService} from './services/analytics.service';
import {AuthService} from './services/auth.service';
import {HomeService} from './services/home.service';
import {Pages, RouterService} from './services/router.service';
import {SettingsService} from './services/settings.service';
import {PresenceService} from './services/presence.service';

import {ColorMode} from './shared/types';

import {styles} from './app.scss';

/** App main component. */
@customElement('deliberation-lab')
export class App extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly authService = core.getService(AuthService);
  private readonly homeService = core.getService(HomeService);
  private readonly routerService = core.getService(RouterService);
  private readonly settingsService = core.getService(SettingsService);
  private readonly presenceService = core.getService(PresenceService);

  override connectedCallback() {
    super.connectedCallback();
  }

  private renderPageContent() {
    const params = this.routerService.activeRoute.params;

    switch (this.routerService.activePage) {
      case Pages.HOME:
        if (!this.authService.isExperimenter) {
          return this.render403();
        }
        return html`
          <page-header></page-header>
          <quick-start-gallery></quick-start-gallery>
          <home-gallery></home-gallery>
        `;
      case Pages.ADMIN:
        return html`
          <page-header></page-header>
          <div class="content">
            <admin-dashboard></admin-dashboard>
          </div>
        `;
      case Pages.SETTINGS:
        return html`
          <page-header></page-header>
          <div class="content info">
            <settings-page .showAccount=${true}></settings-page>
          </div>
        `;
      case Pages.EXPERIMENT:
        if (!this.authService.isExperimenter) {
          return this.render403();
        }
        // Update viewed experiments for current experimenter
        this.authService.updateViewedExperiments(params['experiment']);

        return html` <experiment-dashboard></experiment-dashboard> `;
      case Pages.EXPERIMENT_CREATE:
        if (!this.authService.isExperimenter) {
          return this.render403();
        }
        return html`
          <page-header></page-header>
          <experiment-builder></experiment-builder>
        `;
      case Pages.PARTICIPANT:
        this.presenceService.setupPresence(
          this.routerService.activeRoute.params['experiment'],
          this.routerService.activeRoute.params['participant'],
        );

        return html`
          <page-header></page-header>
          <participant-view></participant-view>
        `;
      case Pages.PARTICIPANT_STAGE:
        // This ensures backwards compatibility
        // from when PARTICIPANT_STAGE was a different route than PARTICIPANT
        this.routerService.navigate(Pages.PARTICIPANT, {
          experiment: params['experiment'],
          participant: params['participant'],
          stage: params['stage'],
        });
        return nothing;
      case Pages.PARTICIPANT_JOIN_COHORT:
        return html`
          <page-header></page-header>
          <cohort-landing></cohort-landing>
        `;
      default:
        return this.render404();
    }
  }

  private render404(message = 'Page not found') {
    return html`<div class="content">404: ${message}</div>`;
  }

  private render403() {
    const renderLogoutButton = () => {
      if (!this.authService.authenticated) return nothing;
      return html`
        <div class="action-buttons">
          <pr-button
            color="error"
            variant="outlined"
            @click=${() => {
              this.authService.signOut();
            }}
          >
            Log out
          </pr-button>
        </div>
      `;
    };

    return html`
      <div class="error-wrapper">
        <div class="error">
          <div>Participants do not have access to this page.</div>
          <div>
            If you are a researcher, contact the owner(s) of this deployment and
            have them add your email address to the allowlist.
          </div>
          ${renderLogoutButton()}
        </div>
      </div>
    `;
  }

  override render() {
    if (
      !this.authService.authenticated &&
      !this.routerService.isParticipantPage &&
      this.routerService.activeRoute.params['experiment'] === undefined
    ) {
      // Render login screen if relevant after initial auth check
      return html`
        <div class="app-wrapper mode--${this.settingsService.colorMode}">
          <div class="content login">
            ${this.authService.initialAuthCheck
              ? html`<login-page></login-page>`
              : nothing}
          </div>
        </div>
      `;
    }

    return html`
      <div class="app-wrapper mode--${this.settingsService.colorMode}">
        <main>
          <div class="content-wrapper">${this.renderPageContent()}</div>
        </main>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'deliberation-lab': App;
  }
}

import '../../pair-components/icon_button';
import '../../pair-components/tooltip';
import '../participant_profile/avatar_icon';
import '../participant_profile/profile_display';
import '../stages/stage_description';
import '../stages/stage_footer';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property, state} from 'lit/decorators.js';

import {core} from '../../core/core';
import {ExperimentManager} from '../../services/experiment.manager';
import {AuthService} from '../../services/auth.service';
import {CohortService} from '../../services/cohort.service';
import {ParticipantService} from '../../services/participant.service';
import {
  ChatStageConfig,
  ChatStagePublicData,
  MediatorProfile,
  MediatorStatus,
  ParticipantProfile,
  convertUnifiedTimestampToTime,
} from '@deliberation-lab/utils';
import {
  getChatStartTimestamp,
  getChatTimeRemainingInSeconds,
} from '../../shared/stage.utils';
import {getHashBasedColor} from '../../shared/utils';
import {styles} from './chat_info_panel.scss';

/** Chat panel view with stage info, timer, participants. */
@customElement('chat-info-panel')
export class ChatPanel extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly experimentManager = core.getService(ExperimentManager);
  private readonly authService = core.getService(AuthService);
  private readonly cohortService = core.getService(CohortService);
  private readonly participantService = core.getService(ParticipantService);

  @property() stage: ChatStageConfig | null = null;
  @property({type: Boolean}) topLayout = false;
  @state() isStatusLoading = false;

  override render() {
    if (!this.stage) {
      return nothing;
    }

    if (this.topLayout) {
      return html`
        <div class="top-layout">${this.renderParticipantList(true)}</div>
      `;
    }

    return html`
      <div class="side-layout">
        <stage-description .stage=${this.stage} noPadding> </stage-description>
        ${this.renderTimer(true)} ${this.renderParticipantList()}
      </div>
    `;
  }

  private renderTimer(showDivider = false) {
    if (!this.stage) return nothing;

    const publicStageData = this.cohortService.stagePublicDataMap[
      this.stage.id
    ] as ChatStagePublicData;
    if (!publicStageData || !this.stage.timeLimitInMinutes) return nothing;

    const renderStatus = () => {
      if (!publicStageData.discussionStartTimestamp) {
        return nothing;
      }

      const end = publicStageData.discussionEndTimestamp;
      if (end) {
        return html`(ended at ${convertUnifiedTimestampToTime(end, false)})`;
      }

      const start = getChatStartTimestamp(
        this.stage?.id ?? '',
        this.cohortService.chatMap,
      );
      if (!start) return nothing;
      return html`(started at ${convertUnifiedTimestampToTime(start, false)})`;
    };

    return html`
      <div
        class=${`countdown ${publicStageData.discussionEndTimestamp ? 'ended' : ''}`}
      >
        ⏱️ Timer: ${this.stage.timeLimitInMinutes} minutes ${renderStatus()}
        ${this.stage.timeMinimumInMinutes &&
        !publicStageData.discussionEndTimestamp
          ? `You must stay on this chat for at least ${this.stage.timeMinimumInMinutes} minutes.`
          : ''}
      </div>
      ${this.topLayout ? nothing : html`<div class="divider"></div>`}
    `;
  }

  private renderParticipantList(topLayout = false) {
    const activeParticipants = this.cohortService.activeParticipants;
    const mediators = this.cohortService.getMediatorsForStage(
      this.stage?.id ?? '',
    );

    if (!this.stage) {
      return nothing;
    }

    return html`
      <div class="panel-item">
        <div class="panel-item-title">
          <div>
            Participants (${activeParticipants.length + mediators.length})
          </div>
          ${topLayout ? this.renderTimer() : nothing}
        </div>
        <div class="panel-list ${topLayout ? 'wrap' : ''}">
          ${activeParticipants.map((participant) =>
            this.renderProfile(participant, topLayout),
          )}
          ${mediators.map((mediator) =>
            this.renderMediator(mediator, topLayout),
          )}
        </div>
      </div>
    `;
  }

  private renderMediator(profile: MediatorProfile, small = false) {
    // TODO: Calculate if mediator is out of messages (maxResponses)
    return html`
      <div class="profile">
        <profile-display
          .profile=${profile}
          .color=${getHashBasedColor(profile.publicId ?? '')}
          displayType=${small ? 'chatSmall' : 'chat'}
        >
        </profile-display>
      </div>
    `;
  }

  private renderProfile(profile: ParticipantProfile, small = false) {
    const isCurrent =
      profile.publicId === this.participantService.profile?.publicId;
    return html`
      <participant-profile-display
        .profile=${profile}
        .showIsSelf=${isCurrent}
        displayType=${small ? 'chatSmall' : 'chat'}
      >
      </participant-profile-display>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'chat-info-panel': ChatPanel;
  }
}

import {observable} from 'mobx';
import {MobxLitElement} from '@adobe/lit-mobx';

import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property} from 'lit/decorators.js';
import {classMap} from 'lit/directives/class-map.js';

import {core} from '../../core/core';
import {ParticipantAnswerService} from '../../services/participant.answer';
import {ParticipantService} from '../../services/participant.service';
import {ExperimentService} from '../../services/experiment.service';

import {styles} from './chat_input.scss';

/** Chat input component */
@customElement('chat-input')
export class ChatInputComponent extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly participantService = core.getService(ParticipantService);
  private readonly participantAnswerService = core.getService(
    ParticipantAnswerService,
  );
  private readonly experimentService = core.getService(ExperimentService);

  @property() stageId = '';
  @property() sendUserInput: (input: string) => void = async (
    input: string,
  ) => {
    if (!this.stageId || !input || input.trim() === '') return;
    await this.participantService.createChatMessage({message: input.trim()});
    this.participantAnswerService.updateChatInput(this.stageId, '');
  };
  @property() storeUserInput: (input: string) => void = (input: string) => {
    if (!this.stageId) return;
    this.participantAnswerService.updateChatInput(this.stageId, input);
  };
  @property() getUserInput: () => string = () => {
    return this.participantAnswerService.getChatInput(this.stageId ?? '');
  };
  @property() isDisabled = false;
  @property() isLoading = false;

  override render() {
    const sendInput = async () => {
      this.isLoading = true;
      await this.sendUserInput(this.getUserInput());
      this.isLoading = false;
    };

    const handleKeyDown = async (e: KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendInput();
      }
    };

    const handleInput = (e: Event) => {
      if (!this.stageId) return;

      const value = (e.target as HTMLTextAreaElement).value;
      this.storeUserInput(value);
    };

    const handlePaste = (e: ClipboardEvent) => {
      // Check if bot protection is enabled
      const botProtection =
        this.experimentService.experiment?.defaultCohortConfig?.botProtection ??
        false;
      if (botProtection) {
        e.preventDefault();
        return false;
      }
    };

    const autoFocus = () => {
      // Only auto-focus chat input if on desktop
      return navigator.maxTouchPoints === 0;
    };

    return html`
      <div class="input">
        <pr-textarea
          size="small"
          placeholder="Send message"
          .value=${this.getUserInput()}
          ?focused=${autoFocus()}
          ?disabled=${this.isDisabled}
          @keydown=${handleKeyDown}
          @input=${handleInput}
          @paste=${handlePaste}
        >
        </pr-textarea>
        <pr-tooltip
          text="Send message"
          color="tertiary"
          variant="outlined"
          position="TOP_END"
        >
          <pr-icon-button
            icon="send"
            variant="tonal"
            ?disabled=${this.isDisabled}
            ?loading=${this.isLoading}
            @click=${sendInput}
          >
          </pr-icon-button>
        </pr-tooltip>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'chat-input': ChatInputComponent;
  }
}

import '../chat/chat_info_panel';
import '../chat/chat_input';
import '../chat/chat_message';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property, state} from 'lit/decorators.js';

import {StageConfig, StageKind} from '@deliberation-lab/utils';

import {styles} from './chat_interface.scss';

/** Chat interface component */
@customElement('chat-interface')
export class ChatInterface extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  @property({type: Object}) stage: StageConfig | undefined = undefined;
  @property({type: Boolean}) showPanel = false;
  @property({type: Boolean}) showInput = true;
  @property({type: Boolean}) disableInput = false;

  // Tracks inner width of window
  @state() mobileView = false;

  private updateResponsiveState = () => {
    this.mobileView = window.innerWidth <= 1024;
  };

  connectedCallback() {
    super.connectedCallback();
    this.updateResponsiveState();
    window.addEventListener('resize', this.updateResponsiveState);
  }

  disconnectedCallback() {
    super.disconnectedCallback();
    window.removeEventListener('resize', this.updateResponsiveState);
  }

  private renderPanel() {
    if (!this.stage) return nothing;
    return html`
      <chat-info-panel .stage=${this.stage} .topLayout=${this.mobileView}>
      </chat-info-panel>
    `;
  }

  override render() {
    if (!this.stage) return nothing;
    return html`
      <div class="interface-wrapper ${this.mobileView ? 'vertical' : ''}">
        ${this.showPanel ? this.renderPanel() : nothing}
        <div class="main-content">
          <div class="chat-content">
            <div class="chat-scroll">
              <div class="chat-history">
                ${
                  this.mobileView
                    ? html`<slot name="mobile-description"></slot>`
                    : nothing
                }
                <slot></slot>
              </div>
            </div>
          </div>
          <slot name="indicators"></slot>
          ${
            !this.showInput
              ? nothing
              : html`<chat-input
                  .stageId=${this.stage?.id ?? ''}
                  .isDisabled=${this.disableInput}
                ></chat-input>`
          }
          </chat-input>
        </div>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'chat-interface': ChatInterface;
  }
}

import '../../pair-components/button';
import '../../pair-components/icon';
import '../../pair-components/icon_button';
import '../../pair-components/textarea';
import '@material/web/checkbox/checkbox.js';

import './structured_prompt_editor';
import {renderShuffleIndicator} from './structured_prompt_editor';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property, state} from 'lit/decorators.js';

import {core} from '../../core/core';
import {ExperimentEditor} from '../../services/experiment.editor';

import {
  AgentPersonaConfig,
  AgentPersonaType,
  ApiKeyType,
  ChatMediatorStructuredOutputConfig,
  ChatPromptConfig,
  PromptItem,
  PromptItemGroup,
  PromptItemType,
  ReasoningLevel,
  StageConfig,
  StageKind,
  StructuredOutputType,
  StructuredOutputDataType,
  StructuredOutputSchema,
  createDefaultPromptFromText,
  isAlwaysThinkingModel,
  isJsonSchemaUnsupportedModel,
  makeStructuredOutputPrompt,
  structuredOutputEnabled,
  TextPromptItem,
} from '@deliberation-lab/utils';
import {LLM_AGENT_AVATARS} from '../../shared/constants';
import {getHashBasedColor} from '../../shared/utils';

import {styles} from './agent_chat_prompt_editor.scss';
import {styles as dialogStyles} from './stage_builder_dialog.scss';

/** Editor for configuring agent chat prompt. */
@customElement('agent-chat-prompt-editor')
export class EditorComponent extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly experimentEditor = core.getService(ExperimentEditor);

  @property() agent: AgentPersonaConfig | undefined = undefined;
  @property() stageNamePrefix = ''; // e.g., number of stage to show before name
  @property() stageId = '';

  @state() showDialog = false;
  @state() isTestButtonLoading = false;

  override render() {
    if (!this.agent) {
      return nothing;
    }

    const stageConfig = this.experimentEditor.getStage(this.stageId);
    if (!stageConfig) {
      return nothing;
    } else if (
      stageConfig.kind !== StageKind.CHAT &&
      stageConfig.kind !== StageKind.PRIVATE_CHAT
    ) {
      return html`
        <div class="section">
          <div class="inactive-stage">
            <div class="section-title inactive">
              ${this.stageNamePrefix}${stageConfig.name}
            </div>
            <div class="description">
              ${this.agent.type === AgentPersonaType.PARTICIPANT
                ? 'No prompt customizations currently available for this stage.'
                : 'Agent mediators do not interact with this stage.'}
            </div>
          </div>
        </div>
      `;
    }

    const promptConfig = this.getPrompt();

    return html`
      <div class="section">
        <div class="section-header">
          <div class="section-title">
            ${this.stageNamePrefix}${stageConfig.name}
          </div>
          ${promptConfig ? this.renderDialogButton() : nothing}
        </div>
        ${this.renderStructuredOutputWarning(this.agent)}
        ${promptConfig?.type === StageKind.CHAT ||
        promptConfig?.type === StageKind.PRIVATE_CHAT
          ? html`
              ${this.renderAgentPrompt(this.agent, promptConfig)}
              ${this.renderDialog(stageConfig, promptConfig)}
            `
          : this.renderAddButton()}
      </div>
    `;
  }

  private renderStructuredOutputWarning(agent: AgentPersonaConfig) {
    const modelName = agent.defaultModelSettings.modelName;

    // Get the prompt config and check if it's a chat config with structuredOutputConfig
    const promptConfig = this.getPrompt();
    const structuredOutputConfig =
      promptConfig &&
      'structuredOutputConfig' in promptConfig &&
      promptConfig.structuredOutputConfig;
    const usesJsonSchema =
      structuredOutputConfig &&
      structuredOutputConfig.type === StructuredOutputType.JSON_SCHEMA;

    // Only warn if using JSON_SCHEMA mode with a model that doesn't support it
    if (isJsonSchemaUnsupportedModel(modelName) && usesJsonSchema) {
      return html`
        <div class="warning">
          Warning: This model does not support native JSON Schema mode. Switch
          to JSON Format mode for structured output.
        </div>
      `;
    }
    return nothing;
  }

  private renderAddButton() {
    return html`
      <pr-button color="error" variant="tonal" @click=${this.addPrompt}>
        Add prompt
      </pr-button>
    `;
  }

  private addPrompt() {
    if (!this.agent) {
      return;
    } else if (this.agent.type === AgentPersonaType.MEDIATOR) {
      this.experimentEditor.addAgentMediatorPrompt(this.agent.id, this.stageId);
    } else if (this.agent.type === AgentPersonaType.PARTICIPANT) {
      this.experimentEditor.addAgentParticipantPrompt(
        this.agent.id,
        this.stageId,
      );
    }
  }

  private getPrompt() {
    return this.experimentEditor.getAgent(this.agent?.id ?? '')?.promptMap[
      this.stageId
    ];
  }

  private deletePrompt() {
    if (!this.agent) {
      return;
    } else if (this.agent.type === AgentPersonaType.MEDIATOR) {
      this.experimentEditor.deleteAgentMediatorPrompt(
        this.agent.id,
        this.stageId,
      );
    } else if (this.agent.type === AgentPersonaType.PARTICIPANT) {
      this.experimentEditor.deleteAgentParticipantPrompt(
        this.agent.id,
        this.stageId,
      );
    }
  }

  private updatePrompt(updatedPrompt: Partial<ChatPromptConfig>) {
    const oldPrompt = this.getPrompt();
    if (
      !this.agent ||
      !oldPrompt ||
      (oldPrompt.type !== StageKind.CHAT &&
        oldPrompt.type !== StageKind.PRIVATE_CHAT)
    ) {
      return;
    }

    const newPrompt = {...oldPrompt, ...updatedPrompt};
    if (this.agent.type === AgentPersonaType.MEDIATOR) {
      this.experimentEditor.updateAgentMediatorPrompt(this.agent.id, newPrompt);
    } else if (this.agent.type === AgentPersonaType.PARTICIPANT) {
      this.experimentEditor.updateAgentParticipantPrompt(
        this.agent.id,
        newPrompt,
      );
    }
  }

  private renderDialog(
    stageConfig: StageConfig,
    promptConfig: ChatPromptConfig,
  ) {
    if (!this.agent || !this.showDialog) return nothing;

    return html`
      <agent-chat-prompt-dialog
        .onClose=${() => {
          this.showDialog = false;
        }}
      >
        <div slot="title">${this.stageNamePrefix}${stageConfig.name}</div>
        <div class="section">
          ${this.renderAgentPrompt(this.agent, promptConfig)}
          <div class="section-title">Prompt settings</div>
          ${this.renderAgentStructuredOutputConfig(this.agent, promptConfig)}
          ${this.renderPromptPreview(promptConfig)}
        </div>
        <div class="divider"></div>
        ${this.renderAgentChatSettings(this.agent, promptConfig)}
        <div class="divider"></div>
        ${this.renderModelReasoningParameters(this.agent, promptConfig)}
        <div class="divider"></div>
        ${this.renderAgentSamplingParameters(this.agent, promptConfig)}
        <div class="divider"></div>
        ${this.renderAgentCustomRequestBodyFields(this.agent, promptConfig)}
        <div class="divider"></div>
        <pr-button color="error" variant="outlined" @click=${this.deletePrompt}>
          Delete prompt
        </pr-button>
      </agent-chat-prompt-dialog>
    `;
  }

  private renderDialogButton() {
    return html`
      <pr-button
        variant="default"
        color="neutral"
        @click=${() => {
          this.showDialog = true;
        }}
      >
        <div class="button-wrapper">
          <pr-icon icon="settings" variant="default" color="neutral"> </pr-icon>
          <div>Advanced settings</div>
        </div>
      </pr-button>
    `;
  }

  private renderAgentPrompt(
    agent: AgentPersonaConfig,
    agentPromptConfig: ChatPromptConfig,
  ) {
    const updatePrompt = (prompt: PromptItem[]) => {
      this.updatePrompt({prompt});
    };

    return html`
      <structured-prompt-editor
        .prompt=${agentPromptConfig.prompt}
        .stageId=${this.stageId}
        .onUpdate=${updatePrompt}
      ></structured-prompt-editor>
    `;
  }

  private renderPromptPreview(agentPromptConfig: ChatPromptConfig) {
    // TODO: Render prompt preview with fake data populating prompt item
    // variables
    const renderPromptItem = (item: PromptItem): unknown => {
      switch (item.type) {
        case PromptItemType.TEXT:
          const textItem = item as TextPromptItem;
          return html`<div>${textItem.text}</div>`;
        case PromptItemType.GROUP:
          const group = item as PromptItemGroup;
          // prettier-ignore
          return html`<details class="prompt-group-preview" open><summary class="chip tertiary">GROUP: ${group.title} ${renderShuffleIndicator(group.shuffleConfig)}</summary><div class="chip-collapsible">${group.items.map((subItem: PromptItem) => renderPromptItem(subItem))}</div></details>`;
        default:
          return html`<div class="chip tertiary">${item.type}</div>`;
      }
    };

    const getPromptItems = () => {
      return agentPromptConfig.prompt.map((item) => renderPromptItem(item));
    };

    const getStructuredOutput = () => {
      const config = agentPromptConfig.structuredOutputConfig;
      if (structuredOutputEnabled(config) && config.schema) {
        return makeStructuredOutputPrompt(config);
      }
      return '';
    };

    return html`
      <div class="code-wrapper">
        <div class="field-title">Prompt preview</div>
        <pre><code>${getPromptItems()}${getStructuredOutput()}</code></pre>
      </div>
    `;
  }

