/** Stage builder dialog */
@customElement('stage-builder-dialog')
export class StageBuilderDialog extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly authService = core.getService(AuthService);
  private readonly experimentEditor = core.getService(ExperimentEditor);

  @property({type: Boolean})
  showTemplates: boolean = false;

  // Used to populate charity allocation template
  @state() private charityDebateConfig: CharityDebateConfig =
    createCharityDebateConfig();
  // Used to populate resource allocation template
  @state() private consensusTopics: string = 'Climate Change';
  // Used to populate book club template
  @state() private bookClubConfig: BookClubConfig = createBookClubConfig();

  // Used to populate policy mediation template
  @state() private policyMediationTopic:
    | 'all'
    | 'publicbroadcast'
    | 'medicaid'
    | 'fr' = 'all';
  @state() private policyMediationMediator:
    | 'all'
    | 'neutral'
    | 'adversarial_0'
    | 'adversarial_100' = 'all';
  @state() private policyMediationTransferStrategy:
    | 'random'
    | 'mixed'
    | 'extremes' = 'random';

  override render() {
    return html`
      <div class="dialog">
        <div class="header">
          ${this.renderTabs()}
          <pr-icon-button
            color="neutral"
            icon="close"
            variant="default"
            @click=${() => {
              this.experimentEditor.toggleStageBuilderDialog();
            }}
          >
          </pr-icon-button>
        </div>
        <div class="body">
          ${this.showTemplates
            ? this.renderTemplateCards()
            : this.renderStageCards()}
        </div>
      </div>
    `;
  }

  private renderTabs() {
    const getClasses = (selected: boolean) => {
      return classMap({
        tab: true,
        selected: selected,
      });
    };

    const toggleView = (showTemplates: boolean) => {
      this.showTemplates = showTemplates;
    };

    return html`
      <div class="tabs">
        <div
          class=${getClasses(!this.showTemplates)}
          @click=${() => {
            toggleView(false);
          }}
        >
          Add stages
        </div>
        <div
          class=${getClasses(this.showTemplates)}
          @click=${() => {
            toggleView(true);
          }}
        >
          Load template
        </div>
      </div>
    `;
  }

  private renderTemplateCards() {
    return html`
      <div class="banner error">
        ⚠️ Loading a template will override all existing stages in your
        configuration!
      </div>
      <div class="card-gallery-wrapper">
        ${this.renderFlipCardTemplateCard()}
        ${this.renderFruitTestTemplateCard()}
        ${this.renderConditionalSurveyTemplateCard()}
        ${this.renderStockInfoGameCard()}
        ${this.renderAssetAllocationTemplateCard()}
        ${this.renderPolicyTemplateCard()} ${this.renderAgentIntegrationCard()}
        ${this.renderBookClubTemplateCard()} ${this.renderPolicyMediationCard()}
      </div>
      ${this.authService.hasResearchTemplateAccess
        ? this.renderResearchTemplateGallery()
        : nothing}
    `;
  }

  // This is a temporary set of hardcoded templates defined in the frontend
  // visible to experimenters who are marked for "research template" access.
  // Eventually, all these templates should be migrated such that they
  // are completely created in the UI and stored in the backend.
  private renderResearchTemplateGallery() {
    return html`
      <div class="banner">
        Note: Only specific experimenters have access to the following research
        templates! This list is controlled by the deployment owners.
      </div>
      <div class="gallery-section">
        <div class="gallery-title">Lost at Sea experiments</div>
        <div class="card-gallery-wrapper">
          ${this.renderLASCard()} ${this.renderLASCard(true)}
        </div>
      </div>
      <div class="gallery-section">
        <div class="gallery-title">Negotiation games</div>
        <div class="card-gallery-wrapper">
          ${this.renderChipNegotiationCard()}
        </div>
      </div>
      <div class="gallery-section">
        <div class="gallery-title">Debate experiments</div>
        <div class="card-gallery-wrapper">
          ${this.renderConsensusDebateCard()}
          ${this.renderCharityDebateTemplateCard()}
          ${this.renderOOTBCharityDebateTemplateCard()}
        </div>
      </div>
    `;
  }

  private renderStageCards() {
    return html`
      <div class="gallery-section">
        <div class="gallery-title">Basic stages</div>
        <div class="card-gallery-wrapper">
          ${this.renderTOSCard()} ${this.renderInfoCard()}
          ${this.renderProfileCard()}
        </div>
      </div>

      <div class="gallery-section">
        <div class="gallery-title">Chat stages</div>
        <div class="card-gallery-wrapper">
          ${this.renderGroupChatCard()} ${this.renderPrivateChatCard()}
        </div>
      </div>

      <div class="gallery-section">
        <div class="gallery-title">Other stages</div>
        <div class="card-gallery-wrapper">
          ${this.renderTransferCard()} ${this.renderSurveyCard()}
          ${this.renderSurveyPerParticipantCard()}
          ${this.renderComprehensionCard()} ${this.renderRankingCard()}
          ${this.renderRevealCard()} ${this.renderPayoutCard()}
          ${this.renderRoleCard()}
        </div>
      </div>

      <div class="gallery-section">
        <div class="gallery-title">
          Experimental stages: ⚠️ use with caution
        </div>
        <div class="card-gallery-wrapper">
          ${this.renderFlipCardCard()} ${this.renderStockInfoCard()}
          ${this.renderAssetAllocationCard()}
          ${this.renderMultiAssetAllocationCard()}
        </div>
      </div>
    `;
  }

  private renderPolicyMediationCard() {
    const loadTemplate = () => {
      // Configuration based on UI inputs
      this.addTemplate(
        getPolicyMediationTemplate({
          minParticipants: 3,
          maxParticipants: 3,
          topicId:
            this.policyMediationTopic === 'all'
              ? undefined
              : this.policyMediationTopic,
          mediatorMode:
            this.policyMediationMediator === 'all'
              ? undefined
              : this.policyMediationMediator,
          transferStrategy: this.policyMediationTransferStrategy,
        }),
      );
    };

    return html`
      <div class="card large-card">
        <div class="title">🤖 Policy Mediation TEMPLATE</div>
        <div>
          Policy Template generated via JSON. Features N=3 gating participants
          logic. You can use the options below to optionally restrict the
          pipeline to a specific format.
        </div>

        <div class="template-controls">
          <div class="subtitle">Policy Topic</div>
          <select
            class="custom-select"
            .value=${this.policyMediationTopic}
            @change=${(e: Event) => {
              this.policyMediationTopic = (e.target as HTMLSelectElement)
                .value as any;
            }}
          >
            <option value="all">Unrestricted (All Topics)</option>
            <option value="publicbroadcast">
              Public Broadcasting (NPR/PBS)
            </option>
            <option value="medicaid">Medicaid Work Requirements</option>
            <option value="fr">Facial Recognition</option>
          </select>

          <div class="subtitle" style="margin-top: 10px;">
            Mediator Strategy
          </div>
          <select
            class="custom-select"
            .value=${this.policyMediationMediator}
            @change=${(e: Event) => {
              this.policyMediationMediator = (e.target as HTMLSelectElement)
                .value as any;
            }}
          >
            <option value="all">Unrestricted (All Strategies)</option>
            <option value="neutral">Neutral Facilitator</option>
            <option value="adversarial_0">
              Adversarial (Persuade to Oppose)
            </option>
            <option value="adversarial_100">
              Adversarial (Persuade to Support)
            </option>
          </select>

          <div class="subtitle" style="margin-top: 10px;">
            Transfer Strategy
          </div>
          <select
            class="custom-select"
            .value=${this.policyMediationTransferStrategy}
            @change=${(e: Event) => {
              this.policyMediationTransferStrategy = (
                e.target as HTMLSelectElement
              ).value as any;
