/** Editor for current cohort (in experiment dashboard) */
@customElement('cohort-editor')
export class Component extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly experimentEditor = core.getService(ExperimentEditor);
  private readonly experimentManager = core.getService(ExperimentManager);
  private readonly experimentService = core.getService(ExperimentService);

  @property() cohort: CohortConfig | undefined = undefined;
  @property() showAgentParticipantDialog = false;
  @property() showAgentMediatorDialog = false;

  @state() isStatusLoading = false;

  override render() {
    return html`
      <div class="experiment-manager">
        ${this.renderHeader()} ${this.renderContent()}
      </div>
    `;
  }

  private renderHeader() {
    const updateCohort = (e: Event) => {
      const id = (e.target as HTMLSelectElement).value;
      this.experimentManager.setCurrentCohortId(id);
    };

    const numCohorts = this.experimentManager.cohortList.length;

    const renderSelection = () => {
      if (numCohorts === 0) return html`Cohort editor`;
      const getNameDisplay = (cohort: CohortConfig) => {
        if (cohort.metadata.name) {
          return `${cohort.metadata.name} (${cohort.id.slice(0, 8)})`;
        }
        return `Cohort ${cohort.id.slice(0, 8)}`;
      };
      return html`
        <div>Edit cohort:</div>
        <select .value=${this.cohort?.id} @change=${updateCohort}>
          ${Object.values(this.experimentManager.cohortMap).map(
            (cohort) =>
              html`<option
                value=${cohort.id}
                ?selected=${cohort.id ===
                this.experimentManager.currentCohortId}
              >
                ${getNameDisplay(cohort)}
              </option>`,
          )}
        </select>
      `;
    };

    const renderAdd = () => {
      if (numCohorts === 0) return nothing;
      return html`
        <pr-tooltip text="Add new cohort" position="LEFT">
          <pr-icon-button
            color="secondary"
            variant="tonal"
            icon="add"
            @click=${this.addCohort}
          >
          </pr-icon-button>
        </pr-tooltip>
      `;
    };

    return html`
      <div class="content-banner">
        <div
          class="back-button"
          @click=${() => {
            this.experimentManager.setShowCohortList(true, true);
          }}
        >
          <pr-icon
            icon="chevron_backward"
            size="small"
            variant="default"
            color="secondary"
          >
          </pr-icon>
          <div>View all cohorts</div>
        </div>
      </div>
      <div class="header">
        <div class="left">${renderSelection()}</div>
        <div class="right">${renderAdd()}</div>
      </div>
    `;
  }

  private async addCohort() {
    const cohortName = this.experimentManager.getNextCohortName();
    const response = await this.experimentManager.createCohort({}, cohortName);
  }

  private renderContent() {
    const numCohorts = this.experimentManager.cohortList.length;

    if (!this.cohort) {
      return html`
        <div class="empty-message">
          ${numCohorts > 0
            ? html`<div>Use the dropdown above to select a cohort.</div>`
            : html`
                <div>
                  Create a cohort to add participants to your experiment. Once
                  you add a cohort, you will no longer be able to edit
                  experiment stages.
                </div>
                <pr-button variant="tonal" @click=${this.addCohort}>
                  Create new cohort
                </pr-button>
              `}
        </div>
      `;
    }

    return html`
      <div class="content">
        <div class="content-header">
          <div>
            <div>
              ${this.cohort?.metadata.name.length === 0
                ? 'Untitled cohort'
                : this.cohort?.metadata.name}
            </div>
            <div class="subtitle">${this.cohort?.id}</div>
          </div>
          <div class="toolbar">
            ${this.renderLockButton()} ${this.renderCopyButton()}
            ${this.renderSettingsButton()}
          </div>
        </div>
        <cohort-filter-controls></cohort-filter-controls>
        ${this.renderParticipantTable(
          'Human participants',
          this.experimentManager.getCohortHumanParticipants(this.cohort.id),
          html`${this.renderAddHumanParticipant()}`,
        )}
        ${this.renderParticipantTable(
          'Agent participants',
          this.experimentManager.getCohortAgentParticipants(this.cohort.id),
          html`${this.renderAddAgentParticipant()}`,
        )}
        ${this.renderMediatorTable(
          'Agent mediators',
          this.experimentManager.getCohortAgentMediators(this.cohort.id),
          html`${this.renderAddMediator()}`,
        )}
        <div class="table-wrapper table-header">
          <details>
            <summary>JSON Config</summary>
            <pre><code>${JSON.stringify(this.cohort, null, 2)}</code></pre>
          </details>
        </div>
      </div>
    `;
  }

  private renderMediatorTable(
    title: string,
    mediators: MediatorProfileExtended[],
    actionBar: TemplateResult,
  ) {
    const renderEmptyMessage = () => {
      if (mediators.length === 0) {
        return html`<div class="table-row">No mediators yet</div>`;
      }
      return nothing;
    };

    const renderMediator = (mediator: MediatorProfileExtended) => {
      const renderStatus = () => {
        return renderMediatorStatusChip(mediator);
      };

      const toggleStatus = async () => {
        this.isStatusLoading = true;
        await this.experimentManager.updateMediatorStatus(
          mediator.privateId,
          mediator.currentStatus === MediatorStatus.ACTIVE
            ? MediatorStatus.PAUSED
            : MediatorStatus.ACTIVE,
        );
        this.isStatusLoading = false;
      };

      const renderPause = () => {
        if (!mediator.agentConfig) {
          return nothing;
        }
        return html`
          <pr-icon-button
            ?loading=${this.isStatusLoading}
            variant="default"
            icon=${mediator.currentStatus === MediatorStatus.PAUSED
              ? 'play_circle'
              : 'pause'}
            @click=${toggleStatus}
          >
          </pr-icon-button>
        `;
      };

      return html`
        <div class="table-row">
          <profile-display .profile=${mediator}></profile-display>
          ${renderStatus()} ${renderPause()}
        </div>
      `;
    };

    return html`
      <div class="table-wrapper">
        <div class="table-header">
          <div>${title}</div>
          <div>${actionBar}</div>
        </div>
        <div class="table-body">
          ${renderEmptyMessage()}
          ${mediators.map((mediator) => renderMediator(mediator))}
        </div>
      </div>
    `;
  }

  private renderParticipantTable(
    title: string,
    allParticipants: ParticipantProfileExtended[],
    actionBar: TemplateResult,
    emptyMessage = 'No participants yet',
  ) {
    const participants = filterParticipantsByStatus(
      allParticipants,
      this.experimentManager.participantStatusFilters,
    );
    const filters = this.experimentManager.participantStatusFilters;
    const hasParticipants = allParticipants.length > 0;

    const renderEmptyMessage = () => {
      if (participants.length === 0) {
        const message =
          hasParticipants && filters.size > 0
            ? 'No participants match the current filter.'
            : emptyMessage;
        return html` <div class="table-row">${message}</div> `;
      }
      return nothing;
    };

    const isOnTransferStage = (participant: ParticipantProfile) => {
      const stage = this.experimentService.getStage(participant.currentStageId);
      if (!stage) return false;
      return stage.kind === StageKind.TRANSFER;
    };

    const sortedParticipants = sortParticipants(participants, {
      sortBy: this.experimentManager.participantSortBy,
      sortDirection: this.experimentManager.participantSortDirection,
      stageIds: this.experimentService.experiment?.stageIds ?? [],
      isOnTransferStage,
    });

    return html`
      <div class="table-wrapper">
        <div class="table-header">
          <div>${title} (${participants.length})</div>
          <div>${actionBar}</div>
        </div>
        <div class="table-body">
          ${renderEmptyMessage()}
          ${sortedParticipants.map(
            (participant) => html`
              <participant-summary
                .participant=${participant}
              ></participant-summary>
            `,
          )}
        </div>
      </div>
    `;
  }

  private isAddParticipantDisabled() {
    if (!this.experimentService.experiment || !this.cohort) {
      return true;
    }
    return (
      this.experimentManager.isFullCohort(this.cohort) ||
      this.experimentService.experiment.cohortLockMap[this.cohort.id]
    );
  }

  private renderAddHumanParticipant() {
    if (!this.cohort) {
      return nothing;
    }

    return html`
      <pr-tooltip text="Add human participant" position="BOTTOM_END">
        <pr-icon-button
          icon="person_add"
          color="tertiary"
          variant="default"
          ?disabled=${this.isAddParticipantDisabled()}
          ?loading=${this.experimentManager.isWritingParticipant}
          @click=${async () => {
            if (!this.cohort) return;
            this.analyticsService.trackButtonClick(ButtonClick.PARTICIPANT_ADD);
            await this.experimentManager.createParticipant(this.cohort.id);
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private renderAddAgentParticipant() {
    return html`
      <pr-tooltip text="Add agent participant" position="BOTTOM_END">
        <pr-icon-button
          icon="person_add"
          color="tertiary"
          variant="default"
          ?disabled=${this.isAddParticipantDisabled()}
          ?loading=${this.experimentManager.isWritingParticipant}
          @click=${async () => {
            if (!this.cohort) return;
            this.showAgentParticipantDialog = true;
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
      ${this.showAgentParticipantDialog
        ? html`<agent-participant-configuration-dialog
            .cohort=${this.cohort}
            @close=${() => {
              this.showAgentParticipantDialog = false;
            }}
          ></agent-participant-configuration-dialog>`
        : nothing}
    `;
  }

  private renderAddMediator() {
    if (!this.cohort) {
      return nothing;
    }

    const availableMediators =
      this.experimentManager.getAvailableMediatorPersonas(this.cohort.id);
    const isLocked = Boolean(
      this.experimentService.experiment?.cohortLockMap[this.cohort.id],
    );
    const tooltipText = isLocked
      ? 'Unlock cohort to add mediators'
      : availableMediators.length === 0
        ? 'No mediator personas available to add'
        : 'Add agent mediator';

    const isDisabled =
      isLocked ||
      availableMediators.length === 0 ||
      this.experimentManager.isWritingMediator;

    return html`
      <pr-tooltip text=${tooltipText} position="BOTTOM_END">
        <pr-icon-button
          icon="person_add"
          color="tertiary"
          variant="default"
          ?disabled=${isDisabled}
          ?loading=${this.experimentManager.isWritingMediator}
          @click=${() => {
            if (isDisabled) return;
            this.showAgentMediatorDialog = true;
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
      ${this.showAgentMediatorDialog
        ? html`<agent-mediator-add-dialog
            .cohort=${this.cohort}
            @close=${() => {
              this.showAgentMediatorDialog = false;
            }}
          ></agent-mediator-add-dialog>`
        : nothing}
    `;
  }

  private renderLockButton() {
    if (!this.cohort) {
      return nothing;
    }

    const isLocked = this.experimentService.experiment
      ? this.experimentService.experiment.cohortLockMap[this.cohort.id]
      : false;

    const onClick = async () => {
      if (!this.cohort) return;
      await this.experimentManager.setCohortLock(this.cohort.id, !isLocked);
    };

    const text = `${isLocked ? 'Unlock' : 'Lock'} this cohort to ${
      isLocked ? 'enable' : 'disable'
    } participants joining`;
    return html`
      <pr-tooltip text=${text} position="BOTTOM_END">
        <pr-icon-button
          icon=${isLocked ? 'lock' : 'lock_open'}
          color=${isLocked ? 'tertiary' : 'secondary'}
          variant="default"
          @click=${onClick}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  async copyCohortLink() {
    if (!this.cohort) return;

    const basePath = window.location.href.substring(
      0,
      window.location.href.indexOf('/#'),
    );
    const link = `${basePath}/#/e/${this.experimentManager.experimentId}/c/${this.cohort.id}`;

    await navigator.clipboard.writeText(link);
    alert('Link copied to clipboard!');
  }

  private renderCopyButton() {
    return html`
      <pr-tooltip text="Copy experiment cohort link" position="BOTTOM_END">
        <pr-icon-button
          icon="content_copy"
          color="neutral"
          variant="default"
          ?disabled=${!this.cohort}
          @click=${this.copyCohortLink}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private renderSettingsButton() {
    return html`
      <pr-tooltip text="Edit cohort metadata" position="BOTTOM_END">
        <pr-icon-button
          icon="settings"
          color="neutral"
          variant="default"
          @click=${() => {
            this.experimentManager.setCohortEditing(this.cohort);
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'cohort-editor': Component;
  }
}

import '../../pair-components/button';
import '../../pair-components/icon_button';
import '../../pair-components/textarea';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property} from 'lit/decorators.js';

import '@material/web/checkbox/checkbox.js';

import {core} from '../../core/core';
import {AnalyticsService, ButtonClick} from '../../services/analytics.service';
import {ExperimentManager} from '../../services/experiment.manager';

import {CohortConfig, CohortParticipantConfig} from '@deliberation-lab/utils';

import {styles} from './cohort_settings_dialog.scss';

/** Cohort settings dialog */
@customElement('cohort-settings-dialog')
export class CohortSettingsDialog extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly experimentManager = core.getService(ExperimentManager);

  override render() {
    if (!this.experimentManager.cohortEditing) {
      return nothing;
    }

    return html`
      <div class="dialog">
        <div class="header">
          <div>Edit cohort</div>
          <pr-icon-button
            color="neutral"
            icon="close"
            variant="default"
            @click=${() => {
              this.experimentManager.setCohortEditing(undefined);
            }}
          >
          </pr-icon-button>
        </div>
        <div class="body">
          ${this.renderName()} ${this.renderDescription()}
          ${this.renderMaxParticipantConfig()}
        </div>
        <div class="footer">
          <pr-button
            color="error"
            variant="tonal"
            @click=${async () => {
              this.analyticsService.trackButtonClick(ButtonClick.COHORT_DELETE);
              await this.experimentManager.deleteCohort(
                this.experimentManager.cohortEditing!.id,
              );
              this.experimentManager.setCurrentCohortId(undefined);
              this.experimentManager.setShowCohortList(true, true);
            }}
          >
            Delete cohort
          </pr-button>
          <pr-button
            ?disabled=${!this.experimentManager.isCreator}
            @click=${() => {
              this.analyticsService.trackButtonClick(
                ButtonClick.COHORT_SAVE_EXISTING,
              );
              const cohort = this.experimentManager.cohortEditing;
              if (!cohort) return;
              this.experimentManager.updateCohortMetadata(
                cohort.id,
                cohort.metadata,
                cohort.participantConfig,
              );
              this.experimentManager.setCohortEditing(undefined);
            }}
          >
            Save
          </pr-button>
        </div>
      </div>
    `;
  }

  private renderName() {
    const updateName = (e: InputEvent) => {
      const name = (e.target as HTMLTextAreaElement).value;
      const cohort = this.experimentManager.cohortEditing;

      if (!cohort) {
        return;
      }

      this.experimentManager.setCohortEditing({
        ...cohort,
        metadata: {...cohort.metadata, name},
      });
    };

    return html`
      <pr-textarea
        label="Name"
        placeholder="Cohort name"
        variant="outlined"
        .value=${this.experimentManager.cohortEditing?.metadata.name ?? ''}
        @input=${updateName}
      >
      </pr-textarea>
    `;
  }

  private renderDescription() {
    const updateDescription = (e: InputEvent) => {
      const description = (e.target as HTMLTextAreaElement).value;
      const cohort = this.experimentManager.cohortEditing;

      if (!cohort) {
        return;
      }

      this.experimentManager.setCohortEditing({
        ...cohort,
        metadata: {...cohort.metadata, description},
      });
    };

    return html`
      <pr-textarea
        label="Description"
        placeholder="Cohort description"
        variant="outlined"
        .value=${this.experimentManager.cohortEditing?.metadata.description ??
        ''}
        @input=${updateDescription}
      >
      </pr-textarea>
    `;
  }

  updateConfig(config: Partial<CohortParticipantConfig> = {}) {
    const cohort = this.experimentManager.cohortEditing;
    if (!cohort) {
      return;
    }
    this.experimentManager.setCohortEditing({
      ...cohort,
      participantConfig: {...cohort.participantConfig, ...config},
    });
  }

  private renderMinParticipantConfig() {
    const cohort = this.experimentManager.cohortEditing;
    if (!cohort) return;

    const minParticipants = cohort.participantConfig.minParticipantsPerCohort;

    const updateCheck = () => {
      if (minParticipants === null) {
        this.updateConfig({minParticipantsPerCohort: 0});
      } else {
        this.updateConfig({minParticipantsPerCohort: null});
      }
    };

    const updateNum = (e: InputEvent) => {
      const num = Number((e.target as HTMLTextAreaElement).value);
      this.updateConfig({minParticipantsPerCohort: num});
    };

    return html`
      <div class="config-item">
        <div class="checkbox-wrapper">
          <md-checkbox
            touch-target="wrapper"
            ?checked=${minParticipants !== null}
            @click=${updateCheck}
          >
          </md-checkbox>
          <div>
            Require minimum number of participants in cohort to start experiment
          </div>
        </div>
        <div class="number-input">
          <label for="minParticipants"> Minimum number of participants </label>
          <input
            type="number"
            id="minParticipants"
            name="minParticipants"
            min="0"
            .value=${minParticipants ?? 0}
            @input=${updateNum}
          />
        </div>
      </div>
    `;
  }

  private renderMaxParticipantConfig() {
    const cohort = this.experimentManager.cohortEditing;
    if (!cohort) return;

    const maxParticipants = cohort.participantConfig.maxParticipantsPerCohort;

    const updateCheck = () => {
      if (maxParticipants === null) {
        this.updateConfig({maxParticipantsPerCohort: 100});
      } else {
        this.updateConfig({maxParticipantsPerCohort: null});
      }
    };

    const updateNum = (e: InputEvent) => {
      const num = Number((e.target as HTMLTextAreaElement).value);
      this.updateConfig({maxParticipantsPerCohort: num});
    };

    return html`
      <div class="config-item">
        <div class="checkbox-wrapper">
          <md-checkbox
            touch-target="wrapper"
            ?checked=${maxParticipants !== null}
            @click=${updateCheck}
          >
          </md-checkbox>
          <div>Limit cohort to maximum number of participants</div>
        </div>
        ${maxParticipants
          ? html`<div class="number-input">
              <label for="maxParticipants">
                Maximum number of participants
              </label>
              <input
                type="number"
                id="maxParticipants"
                name="maxParticipants"
                min="0"
                .value=${maxParticipants ?? 100}
                @input=${updateNum}
              />
            </div>`
          : ''}
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'cohort-settings-dialog': CohortSettingsDialog;
  }
}

import '../../pair-components/button';
import '../experiment_builder/experiment_builder';
import '../experiment_builder/experiment_settings_dialog';
import '../experimenter/experimenter_panel';
import '../header/header';
import '../participant_view/participant_view';
import './cohort_editor';
import './cohort_settings_dialog';
import './cohort_list';
import './participant_stats';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property} from 'lit/decorators.js';

import {core} from '../../core/core';
import {AnalyticsService, ButtonClick} from '../../services/analytics.service';
import {AuthService} from '../../services/auth.service';
import {CohortService} from '../../services/cohort.service';
import {ExperimentManager} from '../../services/experiment.manager';
import {ExperimentService} from '../../services/experiment.service';
import {ParticipantService} from '../../services/participant.service';

import {CohortConfig, StageKind} from '@deliberation-lab/utils';
import {getCohortDescription, getCohortName} from '../../shared/cohort.utils';
import {
  getParticipantStatusDetailText,
  isObsoleteParticipant,
} from '../../shared/participant.utils';

import {styles} from './experiment_dashboard.scss';

/** Experiment dashboard used to view/update cohorts, participants */
@customElement('experiment-dashboard')
export class Component extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly authService = core.getService(AuthService);
  private readonly cohortService = core.getService(CohortService);
  private readonly experimentManager = core.getService(ExperimentManager);
  private readonly experimentService = core.getService(ExperimentService);
  private readonly participantService = core.getService(ParticipantService);

  override render() {
    if (this.experimentManager.isEditingFull) {
      return this.renderEditor();
    }

    if (this.experimentService.isLoading || this.experimentManager.isLoading) {
      return html`<div>Loading...</div>`;
    }

    return html`
      <div class="main-panel">
        <page-header></page-header>
        <experimenter-panel></experimenter-panel>
      </div>
      ${this.renderPanels()} ${this.renderCohortSettingsDialog()}
      ${this.renderExperimentSettingsDialog()}
    `;
  }

  private renderPanels() {
    if (Object.keys(this.experimentService.stageConfigMap).length === 0) {
      return html`
        <div class="cohort-panel">
          <div class="warning">
            ⚠️ Your experiment has no stages. Use the edit button in the left
            panel to add stages in order to unlock cohort and participant
            creation.
          </div>
        </div>
      `;
    }
    return html`
      ${this.renderParticipantStatsPanel()}
      ${this.renderParticipantPreviewPanel()}
    `;
  }

  private renderExperimentSettingsDialog() {
    if (!this.experimentManager.isEditingSettingsDialog) {
      return nothing;
    }

    return html` <experiment-settings-dialog></experiment-settings-dialog> `;
  }

  private renderCohortSettingsDialog() {
    if (!this.experimentManager.cohortEditing) {
      return nothing;
    }

    return html` <cohort-settings-dialog></cohort-settings-dialog> `;
  }

  private renderEditor() {
    return html`
      <div class="editor-wrapper">
        <page-header></page-header>
        <experiment-builder></experiment-builder>
      </div>
    `;
  }

  private renderParticipantStatsPanel() {
    if (!this.experimentManager.showParticipantStats) {
      return nothing;
    }

    if (!this.experimentManager.currentParticipantId) {
      return html`
        <div class="stats-panel">
          ${this.renderParticipantHeader()}
          <div class="empty-message">
            Use the left panel to manage and select participants.
          </div>
        </div>
      `;
    }

    return html`
      <div class="stats-panel">
        ${this.renderParticipantHeader()}
        <div>
          <participant-stats
            .profile=${this.experimentManager.currentParticipant}
          >
          </participant-stats>
        </div>
        <div class="content-wrapper">
          <pre><code>${JSON.stringify(
            this.experimentManager.currentParticipant,
            null,
            2,
          )}</code></pre>
        </div>
      </div>
    `;
  }

  private renderParticipantPreviewPanel() {
    if (!this.experimentManager.showParticipantPreview) {
      return nothing;
    }

    if (!this.experimentManager.currentParticipantId) {
      return html`
        <div class="preview-panel">
          ${this.renderParticipantHeader(true)}
          <div class="empty-message">
            Use the left panel to manage and select participants.
          </div>
        </div>
      `;
    }

    const popupStatus = this.getParticipantStatusText() !== '';
    return html`
      <div class="preview-panel">
        ${this.renderParticipantHeader(true)}
        <participant-view class="${popupStatus ? 'sepia' : ''}">
        </participant-view>
      </div>
    `;
  }

  private renderParticipantHeader(isPreview = false) {
    if (!this.experimentManager.currentParticipant) {
      return nothing;
    }

    const getProfileString = () => {
      const currentParticipant = this.experimentManager.currentParticipant;
      if (!currentParticipant) {
        if (isPreview) {
          return 'Participant preview';
        } else {
          return 'Participant details';
        }
      }
      return `
        ${currentParticipant.avatar ?? ''}
        ${currentParticipant?.name ?? ''}
        (${currentParticipant?.publicId})
      `;
    };

    const renderStatusBanner = () => {
      if (!isPreview) return nothing;
      const text = this.getParticipantStatusText();
      if (text === '') return getProfileString();
      return html` <div class="participant-status-banner">${text}</div> `;
    };

    const renderToggle = () => {
      return html`
        <pr-button
          color="secondary"
          variant="default"
          size="small"
          @click=${() => {
            this.experimentManager.setShowParticipantStats(isPreview, true);
          }}
        >
          Show ${isPreview ? 'stats' : 'preview'}
        </pr-button>
      `;
    };

    return html`
      <div class="header">
        <div class="left">
          ${!isPreview ? getProfileString() : ''} ${renderStatusBanner()}
          ${renderToggle()}
        </div>
        <div class="right">
          ${this.renderDebugModeButton()} ${this.renderTransferMenu()}
        </div>
      </div>
    `;
  }

  private renderDebugModeButton() {
    if (!this.authService.isExperimenter) return nothing;

    const debugMode = this.authService.isDebugMode;
    const tooltipText = `
      Turn debug mode ${debugMode ? 'off' : 'on'}.
      (When on, experimenters can debugging statements in participant preview.
      Note that only some stages have debugging statements.)
    `;

    return html`
      <pr-tooltip text=${tooltipText} position="BOTTOM_END">
        <pr-icon-button
          icon=${debugMode ? 'code_off' : 'code'}
          color="neutral"
          variant="default"
          @click=${() => {
            this.authService.setDebugMode(!debugMode);
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private getParticipantStatusText() {
    const profile = this.experimentManager.currentParticipant;
    const stageId = this.participantService.currentStageViewId ?? '';
    const stage = this.experimentService.getStage(stageId);
    if (!stage || !profile) return '';

    return getParticipantStatusDetailText(
      profile,
      this.cohortService.isStageInWaitingPhase(stage.id),
    );
  }

  private renderTransferMenu() {
    const participant = this.experimentManager.currentParticipant;

    if (!participant || isObsoleteParticipant(participant)) {
      return nothing;
    }

    return html`
      <pr-menu name="Transfer">
        <div class="menu-wrapper">
          ${this.experimentManager.availableCohorts
            .sort((a, b) => {
              return a.metadata.name.localeCompare(b.metadata.name);
            })
            .map((cohort) => this.renderTransferOption(cohort))}
        </div>
      </pr-menu>
    `;
  }

  private renderTransferOption(cohort: CohortConfig) {
    const currentCohortId =
      this.experimentManager.currentParticipant?.currentCohortId;
    // Don't allow transferring to the current cohort.
    if (cohort.id == currentCohortId) {
      return;
    }
    // Don't allow transferring to locked cohorts.
    if (
      this.experimentService.experiment &&
      this.experimentService.experiment.cohortLockMap[cohort.id]
    ) {
      return;
    }

    const initiateTransfer = () => {
      if (!this.experimentManager.currentParticipant) {
        return;
      }

      const participant = this.experimentManager.currentParticipant;
      const cohortParticipants = this.experimentManager.getCohortParticipants(
        cohort.id,
      );

      // Check if there is already a participant with the same name in the cohort.
      if (participant.name) {
        const normalize = (name: string) => name.replace(/\s*\d+$/, '');
        const normalizedName = normalize(participant.name);
        const duplicateParticipant = cohortParticipants.find(
          (p) => p.name && normalize(p.name) === normalizedName,
        );

        if (duplicateParticipant) {
          const isConfirmed = window.confirm(
            `Warning: A participant with a similar name ("${duplicateParticipant.name}") already exists in cohort ${cohort.metadata.name}. Do you still want to transfer?`,
          );
          if (!isConfirmed) return;
        }
      }

      const stage = this.experimentService.getStage(participant.currentStageId);
      if (!stage || !(stage.kind === StageKind.TRANSFER)) {
        const isConfirmed = window.confirm(
          `Participant is not in a transfer stage. Are you sure you want to transfer them?`,
        );
        if (!isConfirmed) return;
      }

      this.analyticsService.trackButtonClick(ButtonClick.TRANSFER_INITIATE);
      this.experimentManager.initiateParticipantTransfer(
        participant.privateId,
        cohort.id,
      );
    };

    return html`
      <div class="menu-item" role="button" @click=${initiateTransfer}>
        <div>${getCohortName(cohort)}</div>
        <div class="subtitle">${getCohortDescription(cohort)}</div>
        <div class="subtitle">
          ${this.experimentManager.getCohortParticipants(
            cohort.id,
            cohort.participantConfig.includeAllParticipantsInCohortCount,
          ).length}
          participants
        </div>
      </div>
    `;
  }
}

