/** Experimenter panel component */
@customElement('experimenter-panel')
export class Panel extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly authService = core.getService(AuthService);
  private readonly experimentManager = core.getService(ExperimentManager);
  private readonly experimentService = core.getService(ExperimentService);
  private readonly participantService = core.getService(ParticipantService);
  private readonly routerService = core.getService(RouterService);

  @state() panelView: PanelView = PanelView.DEFAULT;
  @state() isLoading = false;
  @state() isAckAlertLoading = false;
  @state() participantSearchQuery = '';
  @state() showToast = false;

  private titleInterval: number | undefined = undefined;
  private originalTitle = document.title;
  private disposeReaction: (() => void) | undefined;

  override connectedCallback() {
    super.connectedCallback();
    this.originalTitle = document.title;

    this.disposeReaction = reaction(
      () => this.experimentManager.newAlerts.length,
      (newCount, previousCount: number | undefined) => {
        if (
          newCount > 0 &&
          (previousCount === undefined || newCount > previousCount)
        ) {
          this.startTitleFlash();
          this.showToast = true;
        } else if (newCount === 0) {
          this.stopTitleFlash();
          this.showToast = false;
        }
      },
      {fireImmediately: true},
    );
  }

  override disconnectedCallback() {
    super.disconnectedCallback();
    this.stopTitleFlash();
    if (this.disposeReaction) {
      this.disposeReaction();
    }
  }

  get hasNewAlerts() {
    return this.experimentManager.hasNewAlerts;
  }

  private startTitleFlash() {
    if (this.titleInterval) return;
    let isOriginal = true;
    this.titleInterval = window.setInterval(() => {
      document.title = isOriginal ? '⚠️ New Alert!' : this.originalTitle;
      isOriginal = !isOriginal;
    }, 1000);
  }

  private stopTitleFlash() {
    if (this.titleInterval) {
      clearInterval(this.titleInterval);
      this.titleInterval = undefined;
      document.title = this.originalTitle;
    }
  }

  override render() {
    if (!this.authService.isExperimenter) {
      return nothing;
    }

    const isSelected = (panelView: PanelView) => {
      return this.panelView === panelView;
    };

    return html`
      <div class="panel-wrapper">
        <div class="sidebar">
          <pr-tooltip text="View cohorts" position="RIGHT_END">
            <pr-icon-button
              color="secondary"
              icon="tune"
              size="medium"
              variant=${isSelected(PanelView.DEFAULT) ? 'tonal' : 'default'}
              @click=${() => {
                this.panelView = PanelView.DEFAULT;
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
          <pr-tooltip text="Participant search" position="RIGHT_END">
            <pr-icon-button
              color="secondary"
              icon="search"
              size="medium"
              variant=${isSelected(PanelView.PARTICIPANT_SEARCH)
                ? 'tonal'
                : 'default'}
              @click=${() => {
                this.panelView = PanelView.PARTICIPANT_SEARCH;
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
          <pr-tooltip text="Send manual chat" position="RIGHT_END">
            <pr-icon-button
              color="secondary"
              icon="forum"
              size="medium"
              variant=${isSelected(PanelView.MANUAL_CHAT) ? 'tonal' : 'default'}
              @click=${() => {
                this.panelView = PanelView.MANUAL_CHAT;
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
          <pr-tooltip text="Edit API key" position="RIGHT_END">
            <pr-icon-button
              color="secondary"
              icon="key"
              size="medium"
              variant=${isSelected(PanelView.API_KEY) ? 'tonal' : 'default'}
              @click=${() => {
                this.panelView = PanelView.API_KEY;
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
          <pr-tooltip text="Alerts" position="RIGHT_END">
            <pr-icon-button
              class=${this.hasNewAlerts && !isSelected(PanelView.ALERTS)
                ? 'wiggle'
                : ''}
              color=${this.hasNewAlerts && !isSelected(PanelView.ALERTS)
                ? 'error'
                : 'secondary'}
              icon=${this.hasNewAlerts && !isSelected(PanelView.ALERTS)
                ? 'notifications_active'
                : 'notifications'}
              size="medium"
              variant=${isSelected(PanelView.ALERTS) ? 'tonal' : 'default'}
              @click=${() => {
                this.panelView = PanelView.ALERTS;
                this.showToast = false;
                this.stopTitleFlash();
              }}
            >
            </pr-icon-button>
          </pr-tooltip>

          <pr-tooltip text="View LLM logs" position="RIGHT_END">
            <pr-icon-button
              color="secondary"
              icon="browse_activity"
              size="medium"
              variant=${isSelected(PanelView.LOGS) ? 'tonal' : 'default'}
              @click=${() => {
                this.panelView = PanelView.LOGS;
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
        </div>
        ${this.renderPanelView()} ${this.renderToast()}
      </div>
    `;
  }

  private renderOutdatedWarning() {
    if (!this.experimentService.experiment) return nothing;

    if (this.experimentService.experiment.versionId < EXPERIMENT_VERSION_ID) {
      return html`
        <div class="banner warning">
          <p>
            ⚠️ Warning: This experiment was created with a previous version of
            Deliberate Lab and may not be compatible with the current version
            (e.g., some stages or features may not load or function properly).
          </p>
          <p>
            Contact the deployment owners if you would like to upgrade this
            experiment to the latest version.
          </p>
        </div>
      `;
    }
    return nothing;
  }

  private renderPanelView() {
    switch (this.panelView) {
      case PanelView.PARTICIPANT_SEARCH:
        return this.renderParticipantSearchPanel();
      case PanelView.MANUAL_CHAT:
        return this.renderManualChatPanel();
      case PanelView.API_KEY:
        return this.renderApiKeyPanel();
      case PanelView.ALERTS:
        return this.renderAlertPanel();
      case PanelView.LOGS:
        return this.renderLogsPanel();
      default:
        return this.renderDefaultPanel();
    }
  }

  private renderDefaultPanel() {
    return html`
      <div class="main">
        ${this.renderOutdatedWarning()} ${this.renderCohortListPanel()}
        ${this.renderCohortEditorPanel()}
        <div class="bottom">
          <alpha-toggle></alpha-toggle>
          <div class="subtitle">
            Experiment Version: ${this.experimentService.experiment?.versionId}
            (latest version: ${EXPERIMENT_VERSION_ID})
          </div>
        </div>
      </div>
    `;
  }

  private renderCohortListPanel() {
    if (!this.experimentManager.showCohortList) {
      return nothing;
    }
    return html`
      <div class="cohort-panel">
        <cohort-list></cohort-list>
      </div>
    `;
  }

  private renderCohortEditorPanel() {
    if (!this.experimentManager.showCohortEditor) {
      return nothing;
    }
    return html`
      <div class="cohort-panel">
        <cohort-editor
          .cohort=${this.experimentManager.getCohort(
            this.experimentManager.currentCohortId ?? '',
          )}
        >
        </cohort-editor>
      </div>
    `;
  }

  private renderParticipantSearchPanel() {
    const handleInput = (e: Event) => {
      this.participantSearchQuery = (e.target as HTMLTextAreaElement).value;
    };

    const searchResults =
      this.participantSearchQuery === ''
        ? []
        : this.experimentManager.getParticipantSearchResults(
            this.participantSearchQuery,
          );

    const renderResult = (participant: ParticipantProfileExtended) => {
      const cohortName =
        this.experimentManager.getCurrentParticipantCohort(participant)
          ?.metadata.name ?? '';

      const onResultClick = () => {
        this.experimentManager.setCurrentParticipantId(participant.privateId);
      };

      const isCurrent =
        participant.privateId ===
        this.experimentManager.currentParticipant?.privateId;

      return html`
        <div
          class="search-result ${isCurrent ? 'current' : ''}"
          role="button"
          @click=${onResultClick}
        >
          <div class="title">${participant.publicId}</div>
          <div>${cohortName}</div>
        </div>
      `;
    };

    return html`
      <div class="main">
        <div class="top">
          <div class="header">Participant search</div>
          <pr-textarea
            variant="outlined"
            label="Search by any participant ID (public, private, Prolific) or name"
            @input=${handleInput}
          >
          </pr-textarea>
          <div class="header">Search results</div>
          <div class="search-results">
            ${searchResults.length === 0
              ? html`<div>No results</div>`
              : nothing}
            ${searchResults.map((participant) => renderResult(participant))}
          </div>
        </div>
      </div>
    `;
  }

  private renderManualChatPanel() {
    const stageId = this.participantService.currentStageViewId ?? '';
    const stage = this.experimentService.getStage(stageId);

    if (stage?.kind !== StageKind.CHAT) {
      return html`
        <div class="main">
          <div class="top">
            <div class="header">Manual chat</div>
            <div>Navigate to a chat stage preview to send a message.</div>
          </div>
        </div>
      `;
    }

    return html`
      <div class="main">
        <div class="top">
          <div class="header">Manual chat</div>
          <experimenter-manual-chat></experimenter-manual-chat>
        </div>
      </div>
    `;
  }

  private alertResponseMap = new Map<string, string>();

  private renderAlertPanel() {
    const newAlerts = this.experimentManager.newAlerts;
    const oldAlerts = this.experimentManager.oldAlerts;

    const renderAlert = (alert: AlertMessage) => {
      const cohort = this.experimentManager.getCohort(alert.cohortId);
      const participant =
        this.experimentManager.participantMap[alert.participantId];

      const onAck = (response: string) => {
        this.isAckAlertLoading = true;
        this.experimentManager.ackAlertMessage(
          alert.id,
          alert.participantId,
          response,
        );
        this.alertResponseMap.delete(alert.id);
        this.isAckAlertLoading = false;
      };

      return html`
        <div class="alert ${alert.status === AlertStatus.NEW ? 'new' : ''}">
          <div
            class="alert-top clickable"
            @click=${() => {
              this.experimentManager.setCurrentParticipantId(
                participant.privateId,
              );
              this.experimentManager.setShowParticipantPreview(true, true);
            }}
          >
            <div class="alert-header">
              <div class="left">
                <participant-profile-display .profile=${participant}>
                </participant-profile-display>
                <div class="subtitle">
                  (${cohort?.metadata.name ?? 'Unknown cohort'})
                </div>
              </div>
              <div class="subtitle">
                ${convertUnifiedTimestampToDate(alert.timestamp)}
              </div>
            </div>
            <div class="alert-content">${alert.message}</div>
          </div>
          <div class="alert-bottom">
            <div class="subtitle">Your responses</div>
            ${alert.responses.map(
              (response) => html` <div class="response">${response}</div> `,
            )}
            <div class="alert-response-options">
              <div class="alert-response-input">
                <pr-textarea
                  .value=${this.alertResponseMap.get(alert.id) ?? ''}
                  placeholder="Send a response"
                  @input=${(e: Event) => {
                    this.alertResponseMap.set(
                      alert.id,
                      (e.target as HTMLTextAreaElement).value,
                    );
                  }}
                >
                </pr-textarea>
                <pr-icon-button
                  icon="send"
                  variant="default"
                  @click=${async () => {
                    onAck(this.alertResponseMap.get(alert.id) ?? '');
                  }}
                >
                </pr-icon-button>
              </div>
              ${alert.status === AlertStatus.NEW
                ? html`
                    <pr-tooltip text="Mark as read" position="TOP_END">
                      <pr-icon-button
                        icon="check_circle"
                        variant="default"
                        ?loading=${this.isAckAlertLoading}
                        @click=${() => {
                          onAck('');
                        }}
                      >
                      </pr-icon-button>
                    </pr-tooltip>
                  `
                : nothing}
            </div>
          </div>
        </div>
      `;
    };

    return html`
      <div class="main">
        <div class="top">
          <div class="header">New Alerts</div>
          ${repeat(
            newAlerts,
            (alert) => alert.id,
            (alert) => renderAlert(alert),
          )}
          <div class="header">Past Alerts</div>
          ${repeat(
            oldAlerts,
            (alert) => alert.id,
            (alert) => renderAlert(alert),
          )}
        </div>
      </div>
    `;
  }

  private renderApiKeyPanel() {
    return html`
      <div class="main">
        <div class="top">
          <div class="header">LLM Integration Settingss</div>
          <experimenter-data-editor></experimenter-data-editor>
        </div>
      </div>
    `;
  }

  private renderLogsPanel() {
    return html`
      <div class="main">
        <log-dashboard></log-dashboard>
      </div>
    `;
  }

  private renderToast() {
    if (!this.showToast || !this.hasNewAlerts) return nothing;

    return html`
      <div class="alert-toast">
        <div class="content">
          <pr-icon icon="warning" color="error"></pr-icon>
          <div>You have new alerts!</div>
        </div>
        <pr-icon-button
          icon="close"
          color="error"
          variant="default"
          @click=${() => {
            this.showToast = false;
            this.stopTitleFlash();
          }}
        >
        </pr-icon-button>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'experimenter-panel': Panel;
  }
}

import '../../pair-components/button';
import '../../pair-components/icon_button';
import '../../pair-components/tooltip';
import '../../components/experiment_builder/experiment_builder_nav';
import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property, state} from 'lit/decorators.js';
import {classMap} from 'lit/directives/class-map.js';

import {core} from '../../core/core';
import {ButtonClick, AnalyticsService} from '../../services/analytics.service';
import {AuthService} from '../../services/auth.service';
import {CohortService} from '../../services/cohort.service';
import {ExperimentService} from '../../services/experiment.service';
import {ExperimentEditor} from '../../services/experiment.editor';
import {ExperimentManager} from '../../services/experiment.manager';
import {ParticipantService} from '../../services/participant.service';
import {Pages, RouterService} from '../../services/router.service';

import {BUG_REPORT_URL, DOCUMENTATION_URL} from '../../shared/constants';
import {
  getParticipantInlineDisplay,
  getParticipantStatusDetailText,
} from '../../shared/participant.utils';
import {
  ChatStageConfig,
  ParticipantProfile,
  ParticipantStatus,
} from '@deliberation-lab/utils';

import {styles} from './header.scss';

/** Header component for app pages */
@customElement('page-header')
export class Header extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly experimentEditor = core.getService(ExperimentEditor);
  private readonly experimentManager = core.getService(ExperimentManager);
  private readonly analyticsService = core.getService(AnalyticsService);
  private readonly authService = core.getService(AuthService);
  private readonly cohortService = core.getService(CohortService);
  private readonly experimentService = core.getService(ExperimentService);
  private readonly participantService = core.getService(ParticipantService);
  private readonly routerService = core.getService(RouterService);

  @state() isDownloading = false; // used for experiment download

  override render() {
    if (!this.authService.isExperimenter) {
      return nothing;
    }

    const isDashboard = this.routerService.activePage === Pages.EXPERIMENT;
    const headerClasses = classMap({
      header: true,
      banner: this.isBanner(),
    });

    return html`
      <div class=${headerClasses}>
        <div class="left">
          ${this.renderBackButton()}
          <h1
            class=${isDashboard ? 'short' : ''}
            title=${isDashboard ? this.renderExperimentTitle() : ''}
          >
            ${this.renderTitle()}
          </h1>
        </div>
        <div class="right">${this.renderActions()}</div>
      </div>
    `;
  }

  private isBanner() {
    const activePage = this.routerService.activePage;
    return (
      this.experimentManager.isEditingFull ||
      activePage === Pages.PARTICIPANT ||
      activePage === Pages.PARTICIPANT_JOIN_COHORT
    );
  }

  private renderBackButton() {
    const activePage = this.routerService.activePage;
    const params = this.routerService.activeRoute.params;

    if (activePage === Pages.HOME || activePage === Pages.ADMIN) {
      return nothing;
    }

    const handleClick = () => {
      switch (activePage) {
        case Pages.SETTINGS:
          this.routerService.navigate(Pages.HOME);
          break;
        case Pages.EXPERIMENT:
          if (this.experimentManager.isEditingFull) {
            this.closeEditorWithoutSaving();
          } else {
            this.routerService.navigate(Pages.HOME);
          }
          break;
        case Pages.EXPERIMENT_CREATE:
          this.routerService.navigate(Pages.HOME);
          break;
        case Pages.PARTICIPANT_JOIN_COHORT:
          this.routerService.navigate(Pages.EXPERIMENT, {
            experiment: params['experiment'],
          });
          break;
        case Pages.PARTICIPANT:
          this.routerService.navigate(Pages.EXPERIMENT, {
            experiment: params['experiment'],
            participant: params['participant'],
          });
          break;
        default:
          break;
      }
    };

    return html`
      <pr-icon-button
        color="neutral"
        icon="arrow_back"
        variant="default"
        @click=${handleClick}
      >
      </pr-icon-button>
    `;
  }

  private closeEditorWithoutSaving() {
    if (this.experimentManager.isCreator) {
      // Display confirmation dialog
      const isConfirmed = window.confirm(
        'You may have unsaved changes. Are you sure you want to exit?',
      );
      if (!isConfirmed) return;
    }
    this.experimentManager.setIsEditing(false);
  }

  private renderParticipantProfileBanner(
    profile: ParticipantProfile | undefined,
  ) {
    if (!profile) return;

    const getStageWaitingText = () => {
      const stageId = this.participantService.currentStageViewId ?? '';
      const stage = this.experimentService.getStage(stageId);
      if (!stage || !profile) return '';

      const isWaiting = this.cohortService.isStageInWaitingPhase(stage.id);
      if (isWaiting) {
        return '⏸️ This participant currently sees a wait stage; they are waiting for others in the cohort to catch up.';
      }
      return undefined;
    };

    const detailText = getParticipantStatusDetailText(profile);

    return html`
      Previewing as: ${getParticipantInlineDisplay(profile)}.
      ${detailText.length > 0 ? detailText : getStageWaitingText()}
    `;
  }

  private renderTitle() {
    const activePage = this.routerService.activePage;
    const profile = this.participantService.profile;

    switch (activePage) {
      case Pages.HOME:
        return '🕊️ Deliberate Lab';
      case Pages.ADMIN:
        return 'Admin dashboard';
      case Pages.SETTINGS:
        return 'Settings';
      case Pages.EXPERIMENT:
        return this.renderExperimentTitle();
      case Pages.EXPERIMENT_CREATE:
        return 'New experiment';
      case Pages.PARTICIPANT_JOIN_COHORT:
        return 'Previewing experiment cohort';
      case Pages.PARTICIPANT:
        const stageId = this.participantService.currentStageViewId ?? '';
        const stage = this.experimentService.getStage(stageId);
        if (!stage || !profile) return '';
        return getParticipantStatusDetailText(
          profile,
          this.cohortService.isStageInWaitingPhase(stage.id),
          `Previewing as: ${getParticipantInlineDisplay(profile)}.`,
        );
      default:
        return '';
    }
  }

  private renderExperimentTitle() {
    const title = this.experimentService.experiment?.metadata.name ?? '';
    if (this.experimentManager.isEditingFull) {
      return this.experimentManager.isCreator
        ? `Editing: ${title}`
        : `Previewing config: ${title}`;
    } else {
      return title;
    }
  }

  private renderActions() {
    const activePage = this.routerService.activePage;

    // TODO: Refactor pr-buttons into separate render stages
    switch (activePage) {
      case Pages.HOME:
        return html`
          <pr-tooltip text="Read the documentation" position="BOTTOM_END">
            <pr-icon-button
              icon="article"
              color="secondary"
              variant="default"
              @click=${() => {
                // TODO: Add Analytics tracking for documentation click
                window.open(DOCUMENTATION_URL, '_blank');
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
          <pr-tooltip text="Report a bug" position="BOTTOM_END">
            <pr-icon-button
              icon="bug_report"
              color="secondary"
              variant="default"
              @click=${() => {
                // TODO: Add Analytics tracking for bug report click
                window.open(BUG_REPORT_URL, '_blank');
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
          <pr-tooltip text="View experimenter settings" position="BOTTOM_END">
            <pr-icon-button
              icon="settings"
              color="secondary"
              variant="default"
              @click=${() => {
                this.routerService.navigate(Pages.SETTINGS);
              }}
            >
            </pr-icon-button>
          </pr-tooltip>
        `;
      case Pages.EXPERIMENT_CREATE:
        const errors = this.experimentEditor.getExperimentConfigErrors();
        return html`
          ${errors.length === 0
            ? nothing
            : html` <div class="error">⚠️ ${errors.join(', ')}</div> `}
          <pr-button
            ?loading=${this.experimentEditor.isWritingExperiment}
            ?disabled=${errors.length > 0}
            @click=${async () => {
              this.analyticsService.trackButtonClick(
                ButtonClick.EXPERIMENT_SAVE_NEW,
              );
              const response = await this.experimentEditor.writeExperiment();
              this.experimentEditor.resetExperiment();
              this.routerService.navigate(Pages.EXPERIMENT, {
                experiment: response.id,
              });
            }}
          >
            Save experiment
          </pr-button>
        `;
      case Pages.EXPERIMENT:
        if (this.experimentManager.isEditingFull) {
          if (!this.experimentManager.isCreator) return nothing;

          return html`
            <pr-button
              color="tertiary"
              variant="default"
              @click=${this.closeEditorWithoutSaving}
            >
              Cancel
            </pr-button>
            <pr-button
              color="tertiary"
              variant="tonal"
              ?disabled=${!this.experimentManager.isCreator}
              @click=${() => {
                this.analyticsService.trackButtonClick(
                  ButtonClick.EXPERIMENT_SAVE_EXISTING,
                );
                this.experimentManager.setIsEditing(false, true);
              }}
            >
              Save
            </pr-button>
          `;
        }
        return html`
          ${this.renderExperimentDownloadButton()}
          ${this.renderExperimentForkButton()}
          ${this.renderExperimentEditButton()}
          ${this.renderExperimentDeleteButton()}
        `;
      case Pages.PARTICIPANT:
        return this.renderDebugModeButton();
      default:
        return nothing;
    }
  }

  private renderExperimentDownloadButton() {
    const onClick = async () => {
      this.isDownloading = true;
      await this.experimentManager.downloadExperiment();
      this.isDownloading = false;
    };

    return html`
      <pr-tooltip text="Download experiment data" position="BOTTOM_END">
        <pr-icon-button
          icon="download"
          color="secondary"
          size="small"
          variant="default"
          ?loading=${this.isDownloading}
          @click=${onClick}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private renderExperimentForkButton() {
    const onClick = () => {
      // Display confirmation dialog
      const isConfirmed = window.confirm(
        'This will create a copy of this experiment. Are you sure you want to proceed?',
      );
      if (!isConfirmed) return;
      this.analyticsService.trackButtonClick(ButtonClick.EXPERIMENT_FORK);
      this.experimentManager.forkExperiment();
    };

    return html`
      <pr-tooltip text="Fork experiment" position="BOTTOM_END">
        <pr-icon-button
          icon="fork_right"
          color="secondary"
          size="small"
          variant="default"
          @click=${onClick}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private renderExperimentEditButton() {
    const tooltip = `
      Experiment creators can edit metadata any time
      + can edit stages if users have not joined the experiment.`;

    const onClick = () => {
      this.analyticsService.trackButtonClick(
        this.experimentManager.isCreator
          ? ButtonClick.EXPERIMENT_EDIT
          : ButtonClick.EXPERIMENT_PREVIEW_CONFIG,
      );
      this.experimentManager.setIsEditing(true);
    };

    return html`
      <pr-tooltip text=${tooltip} position="BOTTOM_END">
        <pr-icon-button
          icon="settings"
          color="secondary"
          size="small"
          variant="default"
          @click=${onClick}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private renderExperimentDeleteButton() {
    return html`
      <pr-tooltip text="Delete experiment" position="BOTTOM_END">
        <pr-icon-button
          icon="delete"
          color="error"
          variant="default"
          size="small"
          ?disabled=${!this.experimentManager.isCreator}
          @click=${() => {
            const isConfirmed = window.confirm(
              `Are you sure you want to delete this experiment?`,
            );
            if (!isConfirmed) return;

            this.analyticsService.trackButtonClick(
              ButtonClick.EXPERIMENT_DELETE,
            );
            this.experimentManager.deleteExperiment();
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }

  private renderDebugModeButton() {
    if (!this.authService.isExperimenter) return nothing;

    const debugMode = this.authService.isDebugMode;
    const tooltipText = `
      Turn debug mode ${debugMode ? 'off' : 'on'}.
      (When on, experimenters can debugging statements in participant preview.
      Note that only some stages have debugging statements.)
    `;

    return html`
      <pr-tooltip text=${tooltipText} position="BOTTOM_END">
        <pr-icon-button
          icon=${debugMode ? 'code_off' : 'code'}
          color="neutral"
          variant="default"
          @click=${() => {
            this.authService.setDebugMode(!debugMode);
          }}
        >
        </pr-icon-button>
      </pr-tooltip>
    `;
  }
}

