import '@material/web/slider/slider.js';
import '@material/web/textfield/outlined-text-field.js';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property} from 'lit/decorators.js';
import {classMap} from 'lit/directives/class-map.js';

import {
  CheckSurveyAnswer,
  CheckSurveyQuestion,
  MultipleChoiceDisplayType,
  MultipleChoiceItem,
  MultipleChoiceSurveyAnswer,
  MultipleChoiceSurveyQuestion,
  ParticipantProfile,
  ParticipantStatus,
  SurveyQuestion,
  ScaleSurveyAnswer,
  ScaleSurveyQuestion,
  SurveyQuestionKind,
  SurveyAnswer,
  SurveyPerParticipantStageConfig,
  SurveyStageParticipantAnswer,
  TextSurveyAnswer,
  TextSurveyQuestion,
  isMultipleChoiceImageQuestion,
  isQuestionVisible,
  getVisibleSurveyQuestions,
  isSurveyComplete,
} from '@deliberation-lab/utils';

import {core} from '../../core/core';
import {CohortService} from '../../services/cohort.service';
import {ParticipantService} from '../../services/participant.service';
import {ParticipantAnswerService} from '../../services/participant.answer';

import {styles} from './survey_view.scss';

/** Survey per participant stage view for participants */
@customElement('survey-per-participant-view')
export class SurveyView extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly cohortService = core.getService(CohortService);
  private readonly participantService = core.getService(ParticipantService);
  private readonly participantAnswerService = core.getService(
    ParticipantAnswerService,
  );

  private checkQuestions: string[] = [];

  @property() stage: SurveyPerParticipantStageConfig | undefined = undefined;
  @property() renderSummaryView: boolean = false; // If true, render a minimized summary view.

  private getParticipants() {
    if (!this.stage) return [];

    const allParticipants = this.cohortService.activeParticipants;
    if (this.stage.enableSelfSurvey) {
      return allParticipants;
    }
    return (
      allParticipants.filter(
        (profile) =>
          profile.publicId !== this.participantService.profile?.publicId,
      ) ?? []
    );
  }

  private renderParticipant(profile: ParticipantProfile) {
    const isCurrent =
      profile.publicId === this.participantService.profile?.publicId;

    return html`
      <participant-profile-display
        .profile=${profile}
        displayType="stage"
        .showIsSelf=${isCurrent}
      >
      </participant-profile-display>
    `;
  }

  override render() {
    if (!this.stage) {
      return nothing;
    }

    const questionsComplete = (): boolean => {
      if (!this.stage) return false;
      const participants = this.getParticipants();
      const allStageAnswers = this.participantAnswerService.answerMap;

      for (const participant of participants) {
        const answerMap =
          this.participantAnswerService.getSurveyPerParticipantAnswerMap(
            this.stage.id,
            participant.publicId,
          );

        // Get only the visible questions for this participant
        const visibleQuestions = getVisibleSurveyQuestions(
          this.stage.questions,
          this.stage.id,
          answerMap,
          allStageAnswers,
          participant.publicId,
        );

        if (!isSurveyComplete(visibleQuestions, answerMap)) {
          return false;
        }
      }

      return true;
    };

    const saveAnswers = async () => {
      if (!this.stage) return;

      // Save all answers for this stage
      await this.participantAnswerService.saveSurveyPerParticipantAnswers(
        this.stage.id,
      );
      await this.participantService.progressToNextStage();
    };

    const wrapperStyle = this.renderSummaryView
      ? 'questions-wrapper-condensed'
      : 'questions-wrapper';
    return html`
      ${this.renderSummaryView
        ? ''
        : html`<stage-description .stage=${this.stage}></stage-description>`}
      <div class="${wrapperStyle}">
        ${this.stage.questions.map((question) => this.renderQuestion(question))}
      </div>
      ${this.renderSummaryView
        ? ''
        : html`<stage-footer
            .disabled=${!questionsComplete()}
            .onNextClick=${saveAnswers}
          >
            ${this.stage.progress.showParticipantProgress
              ? html`<progress-stage-completed></progress-stage-completed>`
              : nothing}
          </stage-footer>`}
    `;
  }

  private renderQuestion(question: SurveyQuestion) {
    const allParticipants = this.getParticipants();

    // Filter participants to only those where this question should be visible
    const participants = allParticipants.filter((participant) =>
      this.isQuestionVisibleForParticipant(question, participant),
    );

    // Render the appropriate question type for each visible participant
    switch (question.kind) {
      case SurveyQuestionKind.CHECK:
        return participants.map((participant) =>
          this.renderCheckQuestion(question, participant),
        );
      case SurveyQuestionKind.MULTIPLE_CHOICE:
        return participants.map((participant) =>
          this.renderMultipleChoiceQuestion(question, participant),
        );
      case SurveyQuestionKind.SCALE:
        return participants.map((participant) =>
          this.renderScaleQuestion(question, participant),
        );
      case SurveyQuestionKind.TEXT:
        return participants.map((participant) =>
          this.renderTextQuestion(question, participant),
        );
      default:
        return nothing;
    }
  }

  private isQuestionVisibleForParticipant(
    question: SurveyQuestion,
    participant: ParticipantProfile,
  ): boolean {
    if (!this.stage || !question.condition) {
      return true; // No condition means always show
    }

    // Get current answers for this participant
    const currentAnswers =
      this.participantAnswerService.getSurveyPerParticipantAnswerMap(
        this.stage.id,
        participant.publicId,
      );

    // Get all stage answers
    const allStageAnswers = this.participantAnswerService.answerMap;

    return isQuestionVisible(
      question,
      this.stage.id,
      currentAnswers,
      allStageAnswers,
      participant.publicId, // Pass which participant is being evaluated
    );
  }

  private renderCheckQuestion(
    question: CheckSurveyQuestion,
    participant: ParticipantProfile,
  ) {
    const isChecked = () => {
      if (!this.stage) return;
      // Get answer per participant
      const answer =
        this.participantAnswerService.getSurveyPerParticipantAnswer(
          this.stage.id,
          question.id,
          participant.publicId,
        );
      if (answer && answer.kind === SurveyQuestionKind.CHECK) {
        return answer.isChecked;
      }
      return false;
    };

    const handleCheck = () => {
      const answer: CheckSurveyAnswer = {
        id: question.id,
        kind: SurveyQuestionKind.CHECK,
        isChecked: !isChecked(),
      };
      // Update stage answer
      if (!this.stage) return;
      // Update survey answer accordingly
      this.participantAnswerService.updateSurveyPerParticipantAnswer(
        this.stage.id,
        answer,
        participant.publicId,
      );
    };

    return html`
      <div class="question">
        ${this.renderParticipant(participant)}
        <label class="checkbox-wrapper">
          <md-checkbox
            touch-target="wrapper"
            aria-label=${question.questionTitle}
            ?checked=${isChecked()}
            ?disabled=${this.participantService.disableStage}
            @click=${handleCheck}
          >
          </md-checkbox>
          <div class="question-title">${question.questionTitle}</div>
        </label>
      </div>
    `;
  }

  private renderTextQuestion(
    question: TextSurveyQuestion,
    participant: ParticipantProfile,
  ) {
    if (!this.stage) return;

    const handleTextChange = (e: Event) => {
      if (!this.stage) return;
      const answer = (e.target as HTMLInputElement).value ?? '';
      const textAnswer: TextSurveyAnswer = {
        id: question.id,
        kind: SurveyQuestionKind.TEXT,
        answer,
      };
      // Update per participant
      this.participantAnswerService.updateSurveyPerParticipantAnswer(
        this.stage.id,
        textAnswer,
        participant.publicId,
      );
    };

    // Get answer per participant
    const answer = this.participantAnswerService.getSurveyPerParticipantAnswer(
      this.stage.id,
      question.id,
      participant.publicId,
    );
    const textAnswer =
      answer && answer.kind === SurveyQuestionKind.TEXT ? answer.answer : '';

    // Check if current answer meets requirements for error state
    const minCount = question.minCharCount ?? null;
    const maxCount = question.maxCharCount ?? null;

    const isTooShort = minCount !== null && textAnswer.length < minCount;

    // Build error text (only needed for minimum since maxlength prevents exceeding max)
    const errorText = isTooShort
      ? `Minimum ${minCount} characters required`
      : '';

    return html`
      <div class="question">
        <div class="question-title">${question.questionTitle}</div>
        ${this.renderParticipant(participant)}
        <md-outlined-text-field
          type="textarea"
          placeholder="Type your response"
          .value=${textAnswer}
          ?disabled=${this.participantService.disableStage}
          @input=${handleTextChange}
          .minLength=${minCount ?? nothing}
          .maxLength=${maxCount ?? nothing}
          .error=${isTooShort}
          .errorText=${errorText}
          .counter=${maxCount !== null}
        >
        </md-outlined-text-field>
      </div>
    `;
  }

  private renderMultipleChoiceQuestion(
    question: MultipleChoiceSurveyQuestion,
    participant: ParticipantProfile,
  ) {
    if (
      question.displayType === MultipleChoiceDisplayType.DROPDOWN &&
      !isMultipleChoiceImageQuestion(question)
    ) {
      const selectedChoiceId = (() => {
        if (!this.stage) return '';
        const answer =
          this.participantAnswerService.getSurveyPerParticipantAnswer(
            this.stage.id,
            question.id,
            participant.publicId,
          );
        if (answer && answer.kind === SurveyQuestionKind.MULTIPLE_CHOICE) {
          return answer.choiceId;
        }
        return '';
      })();

      const handleChange = (e: Event) => {
        const value = (e.target as HTMLSelectElement).value;
        if (!value || !this.stage) return;
        const answer: MultipleChoiceSurveyAnswer = {
          id: question.id,
          kind: SurveyQuestionKind.MULTIPLE_CHOICE,
          choiceId: value,
        };
        this.participantAnswerService.updateSurveyPerParticipantAnswer(
          this.stage.id,
          answer,
          participant.publicId,
        );
      };

      return html`
        <div class="radio-question">
          <div class="title">${question.questionTitle}</div>
          ${this.renderParticipant(participant)}
          <md-outlined-select
            class="dropdown-select"
            label="Select an option"
            ?disabled=${this.participantService.disableStage}
            @change=${handleChange}
          >
            ${question.options.map(
              (option) => html`
                <md-select-option
                  value=${option.id}
                  ?selected=${selectedChoiceId === option.id}
                >
                  <div slot="headline">${option.text}</div>
                </md-select-option>
              `,
            )}
          </md-outlined-select>
        </div>
      `;
    }

    const questionWrapperClasses = classMap({
      'radio-question-wrapper': true,
      image: isMultipleChoiceImageQuestion(question),
    });

    return html`
      <div class="radio-question">
        <div class="title">${question.questionTitle}</div>
        ${this.renderParticipant(participant)}
        <div class=${questionWrapperClasses}>
          ${question.options.map((option) =>
            this.renderRadioButton(option, question.id, participant.publicId),
          )}
        </div>
      </div>
    `;
  }

  private isMultipleChoiceMatch(
    questionId: string,
    choiceId: string,
    participantId: string,
  ) {
    if (!this.stage) return;
    // Get answer per participant
    const answer = this.participantAnswerService.getSurveyPerParticipantAnswer(
      this.stage.id,
      questionId,
      participantId,
    );
    if (answer && answer.kind === SurveyQuestionKind.MULTIPLE_CHOICE) {
      return answer?.choiceId === choiceId;
    }
    return false;
  }

  private renderRadioButton(
    choice: MultipleChoiceItem,
    questionId: string,
    participantId: string,
  ) {
    const name = `${questionId}-${participantId}`;
    const id = `${questionId}-${participantId}-${choice.id}`;

    const handleMultipleChoiceClick = (e: Event) => {
      const answer: MultipleChoiceSurveyAnswer = {
        id: questionId,
        kind: SurveyQuestionKind.MULTIPLE_CHOICE,
        choiceId: choice.id,
      };
      // Update stage answer
      if (!this.stage) return;
      this.participantAnswerService.updateSurveyPerParticipantAnswer(
        this.stage.id,
        answer,
        participantId,
      );
    };

    if (choice.imageId.length > 0) {
      const classes = classMap({
        'image-question': true,
        selected:
          this.isMultipleChoiceMatch(questionId, choice.id, participantId) ??
          false,
        disabled: this.participantService.disableStage,
      });

      return html`
        <div class=${classes} @click=${handleMultipleChoiceClick}>
          <div class="img-wrapper">
            <img src=${choice.imageId} />
          </div>
          <div class="radio-button">
            <md-radio
              id=${id}
              name=${questionId}
              value=${choice.id}
              aria-label=${choice.text}
              ?checked=${this.isMultipleChoiceMatch(
                questionId,
                choice.id,
                participantId,
              )}
              ?disabled=${this.participantService.disableStage}
            >
            </md-radio>
            <label for=${id}>${choice.text}</label>
          </div>
        </div>
      `;
    }

    return html`
      <div class="radio-button">
        <md-radio
          id=${id}
          name=${name}
          value=${choice.id}
          aria-label=${choice.text}
          ?checked=${this.isMultipleChoiceMatch(
            questionId,
            choice.id,
            participantId,
          )}
          ?disabled=${this.participantService.disableStage}
          @change=${handleMultipleChoiceClick}
        >
        </md-radio>
        <label for=${id}>${choice.text}</label>
      </div>
    `;
  }

  private renderScaleQuestion(
    question: ScaleSurveyQuestion,
    participant: ParticipantProfile,
  ) {
    const stepSize = question.stepSize ?? 1;
    const scale = [];
    for (let i = question.lowerValue; i <= question.upperValue; i += stepSize) {
      scale.push(i);
    }

    if (question.useSlider) {
      return this.renderScaleSlider(question, participant);
    }

    return html`
      <div class="question">
        <div class="question-title">${question.questionTitle}</div>
        ${this.renderParticipant(participant)}
        <div class="scale labels">
          <div>${question.lowerText}</div>
          <div>${question.middleText}</div>
          <div>${question.upperText}</div>
        </div>
        <div class="scale values">
          ${scale.map((num) =>
            this.renderScaleRadioButton(question, num, participant.publicId),
          )}
        </div>
      </div>
    `;
  }

  private renderScaleSlider(
    question: ScaleSurveyQuestion,
    participant: ParticipantProfile,
  ) {
    const getCurrentValue = () => {
      if (!this.stage) return question.lowerValue;
      const answer =
        this.participantAnswerService.getSurveyPerParticipantAnswer(
          this.stage.id,
          question.id,
          participant.publicId,
        );
      if (answer && answer.kind === SurveyQuestionKind.SCALE) {
        return answer.value;
      }
      return question.lowerValue;
    };

    const handleSliderChange = (e: Event) => {
      const value = Number((e.target as HTMLInputElement).value);
      const answer: ScaleSurveyAnswer = {
        id: question.id,
        kind: SurveyQuestionKind.SCALE,
        value,
      };

      // Update per participant answer
      if (!this.stage) return;
      this.participantAnswerService.updateSurveyPerParticipantAnswer(
        this.stage.id,
        answer,
        participant.publicId,
      );
    };

    return html`
      <div class="question">
        <div class="question-title">${question.questionTitle}</div>
        ${this.renderParticipant(participant)}
        <div class="scale labels">
          <div>${question.lowerText}</div>
          <div>${question.middleText}</div>
          <div>${question.upperText}</div>
        </div>
        <div class="scale slider">
          <md-slider
            min=${question.lowerValue}
            max=${question.upperValue}
            step=${question.stepSize ?? 1}
            value=${getCurrentValue()}
            ticks
            labeled
            ?disabled=${this.participantService.disableStage}
            @input=${handleSliderChange}
          >
          </md-slider>
        </div>
      </div>
    `;
  }

  private renderScaleRadioButton(
    question: ScaleSurveyQuestion,
    value: number,
    participantId: string,
  ) {
    const name = `${question.id}-${participantId}`;
    const id = `${question.id}-${participantId}-${value}`;

    const isScaleChoiceMatch = (value: number) => {
      if (!this.stage) return;
      // Get answer per participant
      const answer =
        this.participantAnswerService.getSurveyPerParticipantAnswer(
          this.stage.id,
          question.id,
          participantId,
        );
      if (answer && answer.kind === SurveyQuestionKind.SCALE) {
        return answer.value === value;
      }
      return false;
    };

    const handleScaleClick = (e: Event) => {
      const value = Number((e.target as HTMLInputElement).value);
      const answer: ScaleSurveyAnswer = {
        id: question.id,
        kind: SurveyQuestionKind.SCALE,
        value,
      };

      // Update stage answer
      if (!this.stage) return;
      this.participantAnswerService.updateSurveyPerParticipantAnswer(
        this.stage.id,
        answer,
        participantId,
      );
    };

    return html`
      <div class="scale-button">
        <md-radio
          id=${id}
          name=${name}
          value=${value}
          ?checked=${isScaleChoiceMatch(value)}
          ?disabled=${this.participantService.disableStage}
          @change=${handleScaleClick}
        >
        </md-radio>
        <label for=${id}>${value}</label>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'survey-per-participant-view': SurveyView;
  }
}

import '../../pair-components/icon';

import {MobxLitElement} from '@adobe/lit-mobx';
import {CSSResultGroup, html, nothing} from 'lit';
import {customElement, property} from 'lit/decorators.js';

import {core} from '../../core/core';
import {CohortService} from '../../services/cohort.service';
import {getParticipantInlineDisplay} from '../../shared/participant.utils';
import {
  CheckSurveyAnswer,
  MultipleChoiceSurveyAnswer,
  MultipleChoiceSurveyQuestion,
  RevealAudience,
  ScaleSurveyAnswer,
  StageKind,
  SurveyRevealItem,
  SurveyStageParticipantAnswer,
  SurveyStagePublicData,
  SurveyStageConfig,
  SurveyQuestion,
  SurveyQuestionKind,
  TextSurveyAnswer,
} from '@deliberation-lab/utils';

import {styles} from './survey_reveal_view.scss';
import {SurveyAnswer} from '@deliberation-lab/utils';

/** Survey reveal view */
@customElement('survey-reveal-view')
export class SurveyReveal extends MobxLitElement {
  static override styles: CSSResultGroup = [styles];

  private readonly cohortService = core.getService(CohortService);

  @property() stage: SurveyStageConfig | undefined = undefined;
  @property() answer: SurveyStageParticipantAnswer | undefined = undefined;
  @property() publicData: SurveyStagePublicData | undefined = undefined;
  @property() item: SurveyRevealItem | undefined = undefined;

  override render() {
    if (!this.stage || !this.item) {
      return nothing;
    }

    const scorableQuestions: SurveyQuestion[] = this.stage.questions.filter(
      (question) => 'correctAnswerId' in question && question.correctAnswerId,
    );

    const questions: SurveyQuestion[] = this.item.revealScorableOnly
      ? scorableQuestions
      : this.stage.questions;

    const showAllParticipants =
      this.item.revealAudience === RevealAudience.ALL_PARTICIPANTS;

    const hasScorableQuestions = scorableQuestions.length > 0;
    return html`
      <h2>
        Results for <b><i>${this.stage.name}</i></b> stage
      </h2>
      ${this.renderTable(questions, showAllParticipants, hasScorableQuestions)}
      <div class="divider"></div>
    `;
  }

  private makeCell(content: string) {
    return html` <div class="table-cell">${content}</div> `;
  }

  private renderTableHeader(
    showAllParticipants: boolean,
    hasScorableQuestions: boolean,
  ) {
    const surveyAnswers = this.cohortService.stagePublicDataMap[this.stage!.id];
    if (!surveyAnswers || surveyAnswers.kind !== StageKind.SURVEY) {
      return '';
    }
    const getGroupCells = () => {
      return html` ${this.cohortService.participantMap &&
      Object.keys(this.cohortService.participantMap)
        .filter((participantId) => {
          const answers = surveyAnswers.participantAnswerMap[participantId];
          return (
            answers && Object.values(answers).some((answer) => answer !== null)
          );
        })
        .map((participantId) =>
          this.makeCell(
            getParticipantInlineDisplay(
              this.cohortService.participantMap[participantId],
            ),
          ),
        )}`;
    };

    return html`
      <div class="table-head">
        <div class="table-row">
          <div class="table-cell number-row">#</div>
          <div class="table-cell">Question</div>
          ${showAllParticipants ? getGroupCells() : this.makeCell('You chose:')}
          ${hasScorableQuestions ? this.makeCell('Correct answer') : ''}
        </div>
      </div>
    `;
  }

  private renderTable(
    questions: SurveyQuestion[],
    showAllParticipants: boolean,
    hasScorableQuestions: boolean,
  ) {
    const surveyAnswers = this.cohortService.stagePublicDataMap[this.stage!.id];
    if (!surveyAnswers || surveyAnswers.kind !== StageKind.SURVEY) {
      return '';
    }

    const filteredParticipantIds = this.cohortService.participantMap
      ? Object.keys(this.cohortService.participantMap).filter(
          (participantId) => {
            const answers = surveyAnswers?.participantAnswerMap[participantId];
            return (
              answers &&
              Object.values(answers).some((answer) => answer !== null)
            );
          },
        )
      : [];

    const allParticipantIds = Object.keys(
      this.cohortService.participantMap || {},
    );
    const hasFilteredParticipants =
      allParticipantIds.length > filteredParticipantIds.length;

    return html`
      <div class="table">
        ${this.renderTableHeader(showAllParticipants, hasScorableQuestions)}
        <div class="table-body">
          ${questions.map((question, index) =>
            this.renderQuestionRow(
              question,
              showAllParticipants,
              hasScorableQuestions,
              index + 1,
            ),
          )}
        </div>
      </div>
    `;
  }

  private renderIcon(correctAnswer: string, selectedAnswer: string) {
    if (correctAnswer === '') {
      return nothing;
    }

    if (correctAnswer === selectedAnswer) {
      return html`<pr-icon color="success" icon="check_circle"></pr-icon>`;
    } else {
      return html`<pr-icon color="error" icon="cancel"></pr-icon>`;
    }
  }

  private renderQuestionRow(
    question: SurveyQuestion,
    showAllParticipants: boolean,
    hasScorableQuestions: boolean,
    rowIndex: number,
  ) {
    if (!this.stage || !this.cohortService.stagePublicDataMap) {
      return '';
    }
    const surveyAnswers = this.cohortService.stagePublicDataMap[this.stage.id];
    if (!surveyAnswers || surveyAnswers.kind !== StageKind.SURVEY) {
      return '';
    }

    const renderMultipleAnswerCells = () => {
      return html`
        ${Object.keys(this.cohortService.participantMap)
          .filter((participantId) => {
            const answers = surveyAnswers.participantAnswerMap[participantId];
            return (
              answers &&
              Object.values(answers).some((answer) => answer !== null)
            );
          })
          .map((participantId) => {
            const participantAnswerMap =
              surveyAnswers.participantAnswerMap[participantId];
            if (!participantAnswerMap || !participantAnswerMap[question.id]) {
              return this.makeCell('');
            }

            const answer = participantAnswerMap[question.id] as SurveyAnswer;
            return this.renderCell(question, answer);
          })}
      `;
    };

    const renderIndividualAnswerCells = () => {
      if (
        !this.answer ||
        !this.answer.answerMap ||
        !this.answer.answerMap[question?.id]
      ) {
        return this.makeCell('');
      }
      return this.renderCell(question, this.answer.answerMap[question.id]);
    };

    const renderCorrectAnswerCell = () => {
      if (
        hasScorableQuestions &&
        'correctAnswerId' in question &&
        question.correctAnswerId
      ) {
        const correctAnswer = question.options.find(
          (option) => option.id === question.correctAnswerId,
        );
        return this.makeCell(correctAnswer?.text ?? '');
      } else {
        return nothing;
      }
    };

    let tooltipText = question.questionTitle;
    if ('options' in question) {
      // TODO: Render HTML.
      tooltipText +=
        '. Options: ' +
        (question as MultipleChoiceSurveyQuestion).options
          .map((item) => item.text)
          .join(', ');
    }

    return html`
      <div class="table-row">
        <div class="table-cell number-row">${rowIndex}</div>
        <div class="table-cell">
          ${question.questionTitle.length > 50
            ? html`
                <pr-tooltip text="${tooltipText}" position="BOTTOM_END">
                  <span style="cursor: pointer">
                    ${question.questionTitle.slice(0, 50)}...
                  </span>
                </pr-tooltip>
              `
            : question.questionTitle}
        </div>
        ${showAllParticipants
          ? renderMultipleAnswerCells()
          : renderIndividualAnswerCells()}
        ${renderCorrectAnswerCell()}
      </div>
    `;
  }

  private renderCell(
    question: SurveyQuestion | null,
    answer: SurveyAnswer | null,
  ) {
    let answerText: string | null = null;

    if (!question || !answer) {
      return this.makeCell('');
    }

    switch (answer.kind) {
      case SurveyQuestionKind.TEXT:
        answerText = (answer as TextSurveyAnswer).answer ?? '-';
        return this.makeCell(answerText!);

      case SurveyQuestionKind.CHECK:
        answerText = (answer as CheckSurveyAnswer).isChecked
          ? '✅ Checked'
          : '☑️ Unchecked';
        return this.makeCell(answerText!);

      case SurveyQuestionKind.MULTIPLE_CHOICE:
        // Assuming question.options is defined
        const selectedOption = (
          question as MultipleChoiceSurveyQuestion
        ).options.find(
          (option) =>
            option.id === (answer as MultipleChoiceSurveyAnswer).choiceId,
        );

        const selectedText = selectedOption
          ? selectedOption.text
          : 'No selection';
        const iconText = this.renderIcon(
          (question as MultipleChoiceSurveyQuestion).correctAnswerId ?? '',
          (answer as MultipleChoiceSurveyAnswer).choiceId ?? null,
        );

        return html` <div class="table-cell">${iconText} ${selectedText}</div>`;

      case SurveyQuestionKind.SCALE:
        answerText = `${(answer as ScaleSurveyAnswer).value}`;
        break;

      default:
        answerText = 'Unknown answer type';
    }

    return this.makeCell(answerText);
  }
}

