  doc,
  getDoc,
  setDoc,
  onSnapshot,
  Timestamp,
  Unsubscribe,
} from 'firebase/firestore';

import {Service} from './service';
import {AdminService} from './admin.service';
import {FirebaseService} from './firebase.service';
import {HomeService} from './home.service';
import {ExperimentManager} from './experiment.manager';
import {Pages, RouterService} from './router.service';

import {
  ExperimenterProfile,
  ExperimenterData,
  createExperimenterData,
} from '@deliberation-lab/utils';

interface ServiceProvider {
  adminService: AdminService;
  experimentManager: ExperimentManager;
  firebaseService: FirebaseService;
  homeService: HomeService;
  routerService: RouterService;
}

export class AuthService extends Service {
  constructor(private readonly sp: ServiceProvider) {
    super();
    makeObservable(this);

    onAuthStateChanged(
      this.sp.firebaseService.auth,
      async (user: User | null) => {
        if (user) {
          // User is signed in, see docs for a list of available properties
          // https://firebase.google.com/docs/reference/js/auth.user
          this.user = user;

          const allowlistDoc = await getDoc(
            doc(
              this.sp.firebaseService.firestore,
              'allowlist',
              user.email ?? '',
            ),
          );

          if (allowlistDoc.exists()) {
            this.isExperimenter = true;
            this.subscribe();
            this.writeExperimenterProfile(user);
            this.sp.homeService.subscribe();
            const experimentId = this.sp.experimentManager.experimentId;
            if (experimentId) {
              this.sp.experimentManager.loadExperimentData(experimentId);
            }

            // Check if admin
            if (allowlistDoc.data().isAdmin) {
              this.sp.adminService.subscribe();
              this.isAdmin = true;
            } else {
              this.isAdmin = false;
            }
            // Check if user has access to research templates
            if (allowlistDoc.data().hasResearchTemplateAccess) {
              this.hasResearchTemplateAccess = true;
            } else {
              this.hasResearchTemplateAccess = false;
            }
          } else {
            this.isExperimenter = false;
            this.isAdmin = false;
          }
        } else {
          // User is signed out
          this.user = null;
          this.isExperimenter = null;
        }
      },
    );
  }

  @observable user: User | null | undefined = undefined;
  @observable isAdmin: boolean | null = null;
  @observable hasResearchTemplateAccess: boolean | null = null;
  @observable isExperimenter: boolean | null = null;
  @observable canEdit = false;

  @observable private debugMode = false;

  @observable unsubscribe: Unsubscribe[] = [];
  @observable experimenterData: ExperimenterData | null = null;
  @observable isExperimentDataLoading = false;

  @computed get userId() {
    return this.user?.uid;
  }

  @computed get userEmail() {
    return this.user?.email;
  }

  @computed get initialAuthCheck() {
    return this.user !== undefined;
  }

  @computed get authenticated() {
    return this.initialAuthCheck && this.user !== null;
  }

  @computed get showAlphaFeatures() {
    return this.experimenterData?.showAlphaFeatures;
  }

  // If true and is experimenter, show debugging components
  // in experimenter preview
  @computed get isDebugMode() {
    return this.isExperimenter && this.debugMode;
  }

  setDebugMode(debugMode: boolean) {
    this.debugMode = debugMode;
  }

  subscribe() {
    this.unsubscribeAll();
    this.isExperimentDataLoading = true;

    // Subscribe to user's experimenter data
    if (!this.userId || !this.userEmail) return;
    this.unsubscribe.push(
      onSnapshot(
        doc(
          this.sp.firebaseService.firestore,
          'experimenterData',
          this.userEmail,
        ),
        (doc) => {
          if (!doc.exists()) {
            this.writeExperimenterData(
              createExperimenterData(this.userId!, this.userEmail!),
            );
          } else {
            const viewedExperiments: string[] = [];
            this.experimenterData = {
              viewedExperiments, // backwards compatibility
              ...doc.data(),
            } as ExperimenterData;
          }
          this.isExperimentDataLoading = false;
        },
      ),
    );
  }

  unsubscribeAll() {
    this.unsubscribe.forEach((unsubscribe) => unsubscribe());
    this.unsubscribe = [];
    this.experimenterData = null;
  }

  setEditPermissions(canEdit: boolean) {
    this.canEdit = !this.isExperimenter ? false : canEdit;
  }

  signInWithGoogle() {
    signInWithPopup(
      this.sp.firebaseService.auth,
      this.sp.firebaseService.provider,
    );
  }

  signOut() {
    signOut(this.sp.firebaseService.auth);
    this.sp.homeService.unsubscribeAll();
    this.sp.routerService.navigate(Pages.HOME);
  }

  /** Experimenter has viewed this experiment before. */
  isViewedExperiment(experimentId: string) {
    return this.experimenterData?.viewedExperiments.find(
      (experiment) => experiment === experimentId,
    );
  }

  /** Update viewed experiments list in ExperimenterData. */
  updateViewedExperiments(experimentId: string) {
    if (!this.experimenterData) {
      return;
    }

    const viewedExperiments = this.experimenterData.viewedExperiments;
    if (viewedExperiments.find((experiment) => experiment === experimentId)) {
      return;
    }

    this.writeExperimenterData({
      ...this.experimenterData,
      viewedExperiments: [...viewedExperiments, experimentId],
    });
  }

  /** Update whether or not to show alpha features. */
  updateAlphaToggle(showAlphaFeatures: boolean) {
    if (!this.experimenterData) {
      return;
    }

    this.writeExperimenterData({
      ...this.experimenterData,
      showAlphaFeatures,
    });
  }

  // *********************************************************************** //
  // FIRESTORE                                                               //
  // *********************************************************************** //

  /** Update experimenter profile. */
  async writeExperimenterProfile(user: User) {
    const profile: ExperimenterProfile = {
      name: user.displayName ?? '',
      email: user.email ?? '',
      lastLogin: Timestamp.now(),
    };

    setDoc(
      doc(this.sp.firebaseService.firestore, 'experimenters', profile.email),
      profile,
    );
  }

  /** Update experimenter private data, e.g., API key. */
  async writeExperimenterData(data: ExperimenterData) {
    setDoc(
      doc(this.sp.firebaseService.firestore, 'experimenterData', data.email),
      data,
    );
  }
}

import {computed, makeObservable, observable} from 'mobx';
import {
  collection,
  doc,
  getDoc,
  getDocs,
  onSnapshot,
  or,
  orderBy,
  query,
  Timestamp,
  Unsubscribe,
  where,
} from 'firebase/firestore';
import {ExperimentService} from './experiment.service';
import {FirebaseService} from './firebase.service';
import {Pages, RouterService} from './router.service';
import {Service} from './service';

import {
  ChatDiscussion,
  ChatMessage,
  ChatStageConfig,
  CohortConfig,
  MediatorProfile,
  MediatorStatus,
  ParticipantProfile,
  ParticipantStatus,
  StageConfig,
  StageKind,
  StagePublicData,
  UnifiedTimestamp,
} from '@deliberation-lab/utils';
import {
  isActiveParticipant,
  isObsoleteParticipant,
  isUnlockedStage,
} from '../shared/participant.utils';

interface ServiceProvider {
  experimentService: ExperimentService;
  firebaseService: FirebaseService;
  routerService: RouterService;
}

/**
 * Cohort data (participants, publicStageData) for current experiment.
 *
 * For participant-specific data (private profile, private answers),
 *  see participant.service.ts
 * For experiment-level configs (stages, roles), see experiment.service.ts
 * To manage cohorts or participants, see experiment.manager.ts
 */
export class CohortService extends Service {
  constructor(private readonly sp: ServiceProvider) {
    super();
    makeObservable(this);
  }

  @observable experimentId: string | null = null;
  @observable cohortId: string | null = null;
  @observable cohortConfig: CohortConfig | null = null;

  // Participants currently in the cohort
  @observable participantMap: Record<string, ParticipantProfile> = {};
  // Participants pending transfer to this cohort
  @observable transferParticipantMap: Record<string, ParticipantProfile> = {};
  // Mediators currently in the cohort
  @observable mediatorMap: Record<string, MediatorProfile> = {};

  @observable stagePublicDataMap: Record<string, StagePublicData> = {};

  // Stage ID to list of non-discussion chat messages
  @observable chatMap: Record<string, ChatMessage[]> = {};
  // Stage ID to map of discussion ID to list of chat messages
  @observable chatDiscussionMap: Record<string, Record<string, ChatMessage[]>> =
    {};

  // Loading
  @observable unsubscribe: Unsubscribe[] = [];
  @observable isMediatorsLoading = false;
  @observable isParticipantsLoading = false;
  @observable isStageDataLoading = false;
  @observable isCohortConfigLoading = false;
  @observable isChatLoading = false;
  @observable isChipLoading = false;

  @computed get isLoading() {
    return (
      this.isParticipantsLoading ||
      this.isStageDataLoading ||
      this.isMediatorsLoading
    );
  }

  set isLoading(value: boolean) {
    this.isParticipantsLoading = value;
    this.isStageDataLoading = value;
    this.isChatLoading = value;
    this.isChipLoading = value;
    this.isMediatorsLoading = value;
  }

  // Returns mediators that are active in the given stage
  getMediatorsForStage(stageId: string) {
    return Object.values(this.mediatorMap).filter(
      (mediator) =>
        mediator.activeStageMap[stageId] &&
        mediator.currentStatus !== MediatorStatus.DELETED,
    );
  }

  getAllParticipants(
    includePendingTransfer = true, // if pending transfer into cohort
  ) {
    if (!includePendingTransfer) {
      return Object.values(this.participantMap);
    }
    return [
      ...Object.values(this.participantMap),
      ...Object.values(this.transferParticipantMap),
    ];
  }

  // Participants currently in the experiment
  // (not dropped out or pending transfer)
  @computed get activeParticipants() {
    return Object.values(this.participantMap).filter((p) =>
      isActiveParticipant(p),
    );
  }

  // Participants who are obsolete but have already passed
  // the given stage should not hold up the waiting page.
  getObsoleteParticipantsPastThisStage(stageId: string) {
    return this.getAllParticipants().filter(
      (participant) =>
        isUnlockedStage(participant, stageId) &&
        isObsoleteParticipant(participant),
    );
  }

  getUnlockedStageParticipants(stageId: string) {
    return this.getAllParticipants().filter(
      (participant) =>
        isUnlockedStage(participant, stageId) &&
        !isObsoleteParticipant(participant),
    );
  }

  getLockedStageParticipants(stageId: string) {
    return this.getAllParticipants().filter(
      (participant) =>
        !isUnlockedStage(participant, stageId) &&
        !isObsoleteParticipant(participant),
    );
  }

  @computed get nonObsoleteParticipants() {
    return this.getAllParticipants().filter((p) => !isObsoleteParticipant(p));
  }

  // Get participants who have completed the stage
  // (excluding obsolete participants)
  getStageCompletedParticipants(stageId: string) {
    return this.getAllParticipants().filter(
      (p) => !isObsoleteParticipant(p) && p.timestamps.completedStages[stageId],
    );
  }

  // Get participants by chat discussion completion
  // (excluding obsolete participants)
  getParticipantsByChatDiscussionCompletion(
    stageId: string,
    discussionId: string,
  ) {
    const completed: ParticipantProfile[] = [];
    const notCompleted: ParticipantProfile[] = [];

    const stage = this.sp.experimentService.getStage(stageId);
    if (!stage || stage.kind !== StageKind.CHAT)
      return {completed, notCompleted};

    const stageData = this.stagePublicDataMap[stageId];
    const discussionMap =
      stageData?.kind === StageKind.CHAT
        ? (stageData.discussionTimestampMap[discussionId] ?? {})
        : {};

    this.getAllParticipants().forEach((participant) => {
      if (!isObsoleteParticipant(participant)) {
        if (discussionMap[participant.publicId]) {
          completed.push(participant);
        } else {
          notCompleted.push(participant);
        }
      }
    });

    return {completed, notCompleted};
  }

  // If stage is in a waiting phase
  isStageInWaitingPhase(stageId: string) {
    // Return false if stage is unlocked for cohort, else true
    return !this.cohortConfig?.stageUnlockMap[stageId];
  }

  // Get number of participants needed to pass waiting phase
  getWaitingPhaseMinParticipants(stageId: string) {
    const stageConfig = this.sp.experimentService.getStage(stageId);
    if (!stageConfig) return 0;

    const numParticipants = this.nonObsoleteParticipants.length;
    const minParticipants = stageConfig.progress.minParticipants;

    if (
      stageConfig.progress.waitForAllParticipants &&
      stageConfig.progress.minParticipants
    ) {
      return Math.max(numParticipants, minParticipants);
    } else if (stageConfig.progress.waitForAllParticipants) {
      return numParticipants;
    } else {
      return minParticipants;
    }
  }

  getChatDiscussionMessages(stageId: string, discussionId: string) {
    if (!this.chatDiscussionMap[stageId]) return [];
    if (!this.chatDiscussionMap[stageId][discussionId]) return [];

    return this.chatDiscussionMap[stageId][discussionId];
  }

  // Returns chat discussion ID (or null if none or finished with all chats)
  // TODO: Return different type of discussion ID based on chat stage kind
  getChatDiscussionId(stageId: string): string | null {
    const stageData = this.stagePublicDataMap[stageId];
    if (!stageData || stageData.kind !== StageKind.CHAT) {
      return null;
    }

    return stageData.currentDiscussionId;
  }

  // Called from participant service on participant snapshot listener
  // (i.e., when participant's current cohort may have changed)
  async loadCohortData(experimentId: string, id: string) {
    if (id === this.cohortId) {
      return;
    }

    this.experimentId = experimentId;
    this.isLoading = true;
    this.cohortId = id;
    this.unsubscribeAll();

    // Subscribe to data
    this.loadCohortConfig();
    this.loadPublicStageData();
    this.loadChatMessages();
    this.loadParticipantProfiles();
    this.loadMediatorProfiles();
  }

  /** Subscribe to current cohort config. */
  private loadCohortConfig() {
    if (!this.experimentId || !this.cohortId) return;

    this.isCohortConfigLoading = true;
    this.unsubscribe.push(
      onSnapshot(
        doc(
          this.sp.firebaseService.firestore,
          'experiments',
          this.experimentId,
          'cohorts',
          this.cohortId,
        ),
        async (doc) => {
          this.cohortConfig = {
            stageUnlockMap: {}, // for backwards compatibility
            ...doc.data(),
          } as CohortConfig;
          this.isCohortConfigLoading = false;
        },
      ),
    );
  }

  /** Subscribe to public stage data. */
  private loadPublicStageData() {
    if (!this.experimentId || !this.cohortId) return;

    this.isStageDataLoading = true;
    this.unsubscribe.push(
      onSnapshot(
        collection(
          this.sp.firebaseService.firestore,
          'experiments',
          this.experimentId,
          'cohorts',
          this.cohortId,
          'publicStageData',
        ),
        (snapshot) => {
          let changedDocs = snapshot.docChanges().map((change) => change.doc);
          if (changedDocs.length === 0) {
            changedDocs = snapshot.docs;
          }

          changedDocs.forEach((doc) => {
            this.stagePublicDataMap[doc.id] = doc.data() as StagePublicData;
          });
          this.isStageDataLoading = false;
        },
      ),
    );
  }

  /** Subscribe to chat message collections for each stage ID. */
  private async loadChatMessages() {
    if (!this.experimentId || !this.cohortId) return;

    // Get stageIds from experiment doc
    // (as they may not have loaded in experiment service yet)
    const experimentRef = doc(
      this.sp.firebaseService.firestore,
      'experiments',
      this.experimentId,
    );
    const experimentSnap = await getDoc(experimentRef);
    if (!experimentSnap.exists()) return;
    const experimentData = experimentSnap.data();
    if (experimentData?.stageIds.length === 0) return;

    this.isChatLoading = true;
    for (const stageId of experimentData.stageIds) {
      this.unsubscribe.push(
        onSnapshot(
          query(
            collection(
              this.sp.firebaseService.firestore,
              'experiments',
              this.experimentId,
              'cohorts',
              this.cohortId,
              'publicStageData',
              stageId,
              'chats',
            ),
            orderBy('timestamp', 'asc'),
          ),
          (snapshot) => {
            let changedDocs = snapshot.docChanges().map((change) => change.doc);
            if (changedDocs.length === 0) {
              changedDocs = snapshot.docs;
            }

            changedDocs.forEach((doc) => {
              if (!this.chatMap[stageId]) {
                this.chatMap[stageId] = [];
              }
              if (!this.chatDiscussionMap[stageId]) {
                this.chatDiscussionMap[stageId] = {};
              }
              const message = {
                senderId: doc.data().participantPublicId ?? '', // backwards compatibility pre version 16
                agentId: '', // backwards compatibility pre version 16
                explanation: '', // backwards compatibility pre version 16
                ...doc.data(),
              } as ChatMessage;
              if (!message.discussionId) {
                this.chatMap[stageId].push(message);
              } else {
                if (!this.chatDiscussionMap[stageId][message.discussionId]) {
                  this.chatDiscussionMap[stageId][message.discussionId] = [];
                }
                this.chatDiscussionMap[stageId][message.discussionId].push(
                  message,
                );
              }
            });
            this.isChatLoading = false;
          },
        ),
      );
    }
  }

  /** Subscribe to participants' public profiles. */
  private loadParticipantProfiles() {
    if (!this.experimentId || !this.cohortId) return;

    this.isParticipantsLoading = true;

    // Clear participant maps before repopulating
    this.participantMap = {};
    this.transferParticipantMap = {};

    // TODO: Use participantPublicData collection once available
    // so that privateIds are not surfaced
    this.unsubscribe.push(
      onSnapshot(
        query(
          collection(
            this.sp.firebaseService.firestore,
            'experiments',
            this.experimentId,
            'participants',
          ),
          or(
            where('currentCohortId', '==', this.cohortId),
            where('transferCohortId', '==', this.cohortId),
          ),
        ),
        (snapshot) => {
          let changedDocs = snapshot.docChanges().map((change) => change.doc);
          if (changedDocs.length === 0) {
            changedDocs = snapshot.docs;
          }

          changedDocs.forEach((doc) => {
            const profile = doc.data() as ParticipantProfile;
            if (profile.currentCohortId === this.cohortId) {
              this.participantMap[profile.publicId] = profile;
              delete this.transferParticipantMap[profile.publicId];
            } else if (profile.transferCohortId === this.cohortId) {
              this.transferParticipantMap[profile.publicId] = profile;
            }
          });
          this.isParticipantsLoading = false;
        },
      ),
    );
  }

  loadMediatorProfiles() {
    if (!this.experimentId || !this.cohortId) return;

    this.isMediatorsLoading = true;

    // Clear mediator map before repopulating
    this.mediatorMap = {};

    // TODO: Use mediatorPublicData collection once available
    // so that agent configs are not surfaced
    this.unsubscribe.push(
      onSnapshot(
        query(
          collection(
            this.sp.firebaseService.firestore,
            'experiments',
            this.experimentId,
            'mediators',
          ),
          or(where('currentCohortId', '==', this.cohortId)),
        ),
        (snapshot) => {
          let changedDocs = snapshot.docChanges().map((change) => change.doc);
          if (changedDocs.length === 0) {
            changedDocs = snapshot.docs;
          }

          changedDocs.forEach((doc) => {
            const profile = doc.data() as MediatorProfile;
            this.mediatorMap[profile.publicId] = profile;
          });
          this.isMediatorsLoading = false;
        },
      ),
    );
  }

  unsubscribeAll() {
    this.unsubscribe.forEach((unsubscribe) => unsubscribe());
    this.unsubscribe = [];

    // Reset stage configs
    this.cohortConfig = null;
    this.participantMap = {};
    this.chatMap = {};
    this.chatDiscussionMap = {};
    this.transferParticipantMap = {};
    this.stagePublicDataMap = {};
    this.mediatorMap = {};
  }

  reset() {
    this.cohortId = null;
    this.experimentId = null;
    this.unsubscribeAll();
  }
}

import {
  AgentMediatorTemplate,
  AgentMediatorPersonaConfig,
  AgentParticipantPersonaConfig,
  AgentPersonaType,
  AgentParticipantTemplate,
  ApiKeyType,
  CohortParticipantConfig,
  Experiment,
  ExperimentTemplate,
  MediatorPromptConfig,
  MetadataConfig,
  ParticipantPromptConfig,
  PermissionsConfig,
  ProlificConfig,
  StageConfig,
  StageKind,
  StageManager,
  VariableConfig,
  STAGE_MANAGER,
  checkApiKeyExists,
  createAgentMediatorPersonaConfig,
  createAgentParticipantPersonaConfig,
  createExperimentConfig,
  createMetadataConfig,
  createPermissionsConfig,
  createProlificConfig,
  generateId,
} from '@deliberation-lab/utils';
import {Timestamp} from 'firebase/firestore';
import {computed, makeObservable, observable} from 'mobx';
import {
  writeExperimentCallable,
  updateExperimentCallable,
} from '../shared/callables';

import {AuthService} from './auth.service';
import {ExperimentManager} from './experiment.manager';
import {FirebaseService} from './firebase.service';
import {Service} from './service';
import {setMustWaitForAllParticipants} from '../shared/experiment.utils';

interface ServiceProvider {
  authService: AuthService;
  experimentManager: ExperimentManager;
  firebaseService: FirebaseService;
}

/**
 * Create/edit and save experiment.
 */
export class ExperimentEditor extends Service {
  constructor(private readonly sp: ServiceProvider) {
    super();
    makeObservable(this);
  }

  // Experiment config
  // WARNING: Use this.stages as source of truth for stage ordering,
  // not this.experiment.stageIds (which will be overridden)
  // TODO: Consolidate these fields into ExperimentTemplate
  @observable experiment: Experiment = createExperimentConfig();
  @observable stages: StageConfig[] = [];
  @observable agentMediators: AgentMediatorTemplate[] = [];

  // WARNING: We are not currently permitting agent participant peraons to be
  // set in the editor (so this list is expected to be empty).
  // Rather, agent participants are defined on the spot in the experiment
  // dashboard and will use a default set of prompts (see PR #864)
  @observable agentParticipants: AgentParticipantTemplate[] = [];

  // Loading
  @observable isWritingExperiment = false;

  // Editor tooling
  @observable currentAgentId: string | undefined = undefined;
  @observable currentStageId: string | undefined = undefined;
  @observable showStageBuilderDialog = false;
  @observable showTemplatesTab = false;

  // **************************************************************************
  // EXPERIMENT LOADING
  // **************************************************************************

  getExperimentConfigErrors() {
    const errors: string[] = [];

    if (this.experiment.metadata.name.length === 0) {
      errors.push('Experiment does not have a name');
    }

    if (this.stages.length === 0) {
      errors.push('You must add at least one stage to your experiment');
    }

    // Check if relevant API key is set up for agents
    const hasAgentsWithApiType = (apiType: ApiKeyType) => {
      const agents = [...this.agentMediators, ...this.agentParticipants].filter(
        (agent) => agent.persona.defaultModelSettings.apiType === apiType,
      );
      return (
        agents.length > 0 &&
        !checkApiKeyExists(apiType, this.sp.authService.experimenterData)
      );
    };

    const renderApiErrorMessage = (apiType: ApiKeyType) => {
      if (hasAgentsWithApiType(apiType)) {
        errors.push(
          `Your experiment includes agents that use the ${apiType} API, but you have not set your API key yet`,
        );
      }
    };
    renderApiErrorMessage(ApiKeyType.GEMINI_API_KEY);
    renderApiErrorMessage(ApiKeyType.OPENAI_API_KEY);
    renderApiErrorMessage(ApiKeyType.OLLAMA_CUSTOM_URL);

    for (const stage of this.stages) {
      switch (stage.kind) {
        case StageKind.SURVEY:
          // Ensure all questions have a non-empty title
          stage.questions.forEach((question, index) => {
            if (question.questionTitle === '') {
              errors.push(
                `${stage.name} question ${index + 1} is missing a title`,
              );
            }
          });
          break;
      }
    }
    return errors;
  }

  getMediatorAllowedStages() {
    return this.stages.filter(
      (stage) =>
        stage.kind === StageKind.CHAT || stage.kind === StageKind.PRIVATE_CHAT,
    );
  }

  @computed get canEditStages() {
    return this.sp.experimentManager.canEditExperimentStages;
  }

  loadExperiment(experiment: Experiment, stages: StageConfig[]) {
    this.experiment = experiment;
    this.setStages(stages);
  }

  loadTemplate(template: ExperimentTemplate, loadExperimentId = false) {
    // Only copy over relevant parts (e.g., not template ID)
    this.experiment = createExperimentConfig(template.stageConfigs, {
      id: loadExperimentId ? template.experiment.id : generateId(),
      metadata: template.experiment.metadata,
      permissions: template.experiment.permissions,
      defaultCohortConfig: template.experiment.defaultCohortConfig,
      prolificConfig: template.experiment.prolificConfig,
      variableConfigs: template.experiment.variableConfigs,
      cohortDefinitions: template.experiment.cohortDefinitions,
    });
    this.setStages(template.stageConfigs);
    this.setAgentMediators(template.agentMediators);
    this.setAgentParticipants(template.agentParticipants);
  }

  resetExperiment() {
    this.experiment = createExperimentConfig();
    this.stages = [];
    this.agentMediators = [];
    this.agentParticipants = [];
  }

  // **************************************************************************
  // EXPERIMENT CONFIG
  // **************************************************************************

  // Return true if creator or admin
  @computed get isCreator() {
    return (
      this.sp.authService.userEmail === this.experiment.metadata.creator ||
      this.sp.authService.isAdmin ||
      this.experiment.metadata.creator === ''
    );
  }

  isInitializedExperiment() {
    return this.experiment.id.length > 0;
  }

  addVariableConfig(variable: VariableConfig) {
    this.experiment.variableConfigs = [
      ...(this.experiment.variableConfigs ?? []),
      variable,
    ];
  }

  // TODO: Ensure that variable names are unique
  updateVariableConfig(newVariable: VariableConfig, index: number) {
    if (!this.experiment.variableConfigs) {
      return false;
    }
    if (index >= 0) {
      this.experiment.variableConfigs = [
        ...this.experiment.variableConfigs.slice(0, index),
        newVariable,
        ...this.experiment.variableConfigs.slice(index + 1),
      ];
    }
  }

  updateMetadata(metadata: Partial<MetadataConfig>) {
    this.experiment.metadata = {...this.experiment.metadata, ...metadata};
  }

  updatePermissions(permissions: Partial<PermissionsConfig>) {
    this.experiment.permissions = {
      ...this.experiment.permissions,
      ...permissions,
    };
  }

  updateCohortConfig(config: Partial<CohortParticipantConfig>) {
    this.experiment.defaultCohortConfig = {
      ...this.experiment.defaultCohortConfig,
      ...config,
    };
  }

  updateProlificConfig(config: Partial<ProlificConfig>) {
    this.experiment.prolificConfig = {
      ...this.experiment.prolificConfig,
      ...config,
    };
  }

  // **************************************************************************
  // STAGE CONFIGS
  // **************************************************************************

  setCurrentStageId(id: string | undefined) {
    this.currentStageId = id;
  }

  jumpToLastStage() {
    const stage = this.stages[this.stages.length - 1];
    const id = stage ? stage.id : undefined;
    this.setCurrentStageId(id);
  }

  @computed get currentStage() {
    return this.stages.find((stage) => stage.id === this.currentStageId);
  }

  hasStageKind(kind: StageKind) {
    return this.stages.findIndex((stage) => stage.kind === kind) !== -1;
  }

  updateStage(newStage: StageConfig) {
    const index = this.stages.findIndex((stage) => stage.id === newStage.id);
    if (index >= 0) {
      // Update waitForAllParticipants if relevant
      setMustWaitForAllParticipants(newStage, this.stages);
      // Update stage in list
      this.stages[index] = newStage;
    }
  }

  setStages(stages: StageConfig[]) {
    // Make sure all new stages have waitForAllParticipants configured correctly
    for (const stage of stages) {
      setMustWaitForAllParticipants(stage, stages);
    }
    // Set stages
    this.stages = stages;
  }

  addStage(stage: StageConfig) {
    // Check if stage will have waitForAllParticipants dependencies
    // after it's added
    setMustWaitForAllParticipants(stage, [...this.stages, stage]);
    // Add stage
    this.stages.push(stage);
  }

  getStage(stageId: string) {
    return this.stages.find((stage) => stage.id === stageId);
  }

  deleteStage(index: number) {
    this.stages = [
      ...this.stages.slice(0, index),
      ...this.stages.slice(index + 1),
    ];
  }

  moveStageUp(index: number) {
    this.stages = [
      ...this.stages.slice(0, index - 1),
      ...this.stages.slice(index, index + 1),
      ...this.stages.slice(index - 1, index),
      ...this.stages.slice(index + 1),
    ];
  }

  moveStageDown(index: number) {
    this.stages = [
      ...this.stages.slice(0, index),
      ...this.stages.slice(index + 1, index + 2),
      ...this.stages.slice(index, index + 1),
      ...this.stages.slice(index + 2),
    ];
  }

  toggleStageBuilderDialog(showTemplates: boolean = false) {
    this.showStageBuilderDialog = !this.showStageBuilderDialog;
    this.showTemplatesTab = showTemplates;
  }

  // **************************************************************************
  // AGENT PERSONA CONFIGS
  // **************************************************************************
  @computed get currentAgent() {
    return [...this.agentMediators, ...this.agentParticipants].find(
      (agent) => agent.persona.id === this.currentAgentId,
    );
  }

  setCurrentAgentId(id: string) {
    this.currentAgentId = id;
  }

  setAgentIdToLatest(isMediator: boolean = true) {
    const agents = isMediator ? this.agentMediators : this.agentParticipants;
    if (agents.length === 0) {
      this.setCurrentAgentId('');
    } else {
      this.setCurrentAgentId(agents[agents.length - 1].persona.id);
    }
  }

  setAgentMediators(templates: AgentMediatorTemplate[]) {
    this.agentMediators = templates;
  }

  // WARNING: We are not currently allowing experimenters to edit
  // agent participant personas in the editor.
  setAgentParticipants(templates: AgentParticipantTemplate[]) {
    this.agentParticipants = templates;
  }

  addAgentMediator(setAsCurrent = true) {
    const persona = createAgentMediatorPersonaConfig();
    this.agentMediators.push({
      persona,
      promptMap: {},
    });
    if (setAsCurrent) {
      this.setCurrentAgentId(persona.id);
    }
  }

  // WARNING: We are not currently allowing experimenters to edit
  // agent participant personas in the editor.
  addAgentParticipant(setAsCurrent = true) {
    const persona = createAgentParticipantPersonaConfig();
    this.agentParticipants.push({
      persona,
      promptMap: {},
    });
    if (setAsCurrent) {
      this.setCurrentAgentId(persona.id);
    }
  }

  deleteAgentMediator(id: string) {
    const agentIndex = this.agentMediators.findIndex(
      (agent) => agent.persona.id === id,
    );
    if (agentIndex === -1) return;
    this.agentMediators = [
      ...this.agentMediators.slice(0, agentIndex),
      ...this.agentMediators.slice(agentIndex + 1),
    ];
  }

  // WARNING: We are not currently allowing experimenters to edit
  // agent participant personas in the editor.
  deleteAgentParticipant(id: string) {
    const agentIndex = this.agentParticipants.findIndex(
      (agent) => agent.persona.id === id,
    );
    if (agentIndex === -1) return;
    this.agentParticipants = [
      ...this.agentParticipants.slice(0, agentIndex),
      ...this.agentParticipants.slice(agentIndex + 1),
    ];
  }

  getAgent(id: string) {
    const mediator = this.getAgentMediator(id);
    return mediator ? mediator : this.getAgentParticipant(id);
  }

  getAgentMediator(id: string) {
    return this.agentMediators.find((agent) => agent.persona.id === id);
  }

  // WARNING: We are not currently allowing experimenters to edit
  // agent participant personas in the editor.
  getAgentParticipant(id: string) {
    return this.agentParticipants.find((agent) => agent.persona.id === id);
  }

  addAgentMediatorPrompt(agentId: string, stageId: string) {
    const agent = this.getAgentMediator(agentId);
    const stage = this.getStage(stageId);
    if (!agent || !stage) return;
    // Can only add mediator to chat prompts for now
    if (
      stage.kind !== StageKind.CHAT &&
      stage.kind !== StageKind.PRIVATE_CHAT
    ) {
      return;
    }

    const prompt = STAGE_MANAGER.getDefaultMediatorStructuredPrompt(stage);

    if (prompt) {
      agent.promptMap[stageId] = prompt;
    }
  }

  // WARNING: We are not currently allowing experimenters to edit
  // agent participant personas in the editor.
  addAgentParticipantPrompt(agentId: string, stageId: string) {
    const agent = this.getAgentParticipant(agentId);
    const stage = this.getStage(stageId);
    if (!agent || !stage) return;

    const prompt = STAGE_MANAGER.getDefaultParticipantStructuredPrompt(stage);
    if (prompt) {
      agent.promptMap[stageId] = prompt;
    }
  }

  updateAgentMediatorPersona(
    id: string,
    updatedPersona: Partial<AgentMediatorPersonaConfig>,
  ) {
    const agentIndex = this.agentMediators.findIndex(
      (agent) => agent.persona.id === id,
    );
    if (agentIndex === -1) return;

    const oldAgent = this.agentMediators[agentIndex];
    this.agentMediators = [
      ...this.agentMediators.slice(0, agentIndex),
      {
        persona: {...oldAgent.persona, ...updatedPersona},
        promptMap: oldAgent.promptMap,
      },
      ...this.agentMediators.slice(agentIndex + 1),
    ];
  }

  updateAgentMediatorPrompt(id: string, updatedPrompt: MediatorPromptConfig) {
    const agent = this.getAgentMediator(id);
    if (!agent) return;
    agent.promptMap[updatedPrompt.id] = updatedPrompt;
  }

  deleteAgentMediatorPrompt(agentId: string, stageId: string) {
    const agent = this.getAgentMediator(agentId);
    if (!agent) return;
    delete agent.promptMap[stageId];
  }

  updateAgentParticipantPrompt(
    id: string,
    updatedPrompt: ParticipantPromptConfig,
  ) {
    // TODO: Permit non-chat prompt edits
    if (
      updatedPrompt.type !== StageKind.CHAT &&
      updatedPrompt.type !== StageKind.PRIVATE_CHAT
    ) {
      return;
    }
    const agent = this.getAgentParticipant(id);
    if (!agent) return;
    agent.promptMap[updatedPrompt.id] = updatedPrompt;
  }

  deleteAgentParticipantPrompt(agentId: string, stageId: string) {
    const agent = this.getAgentParticipant(agentId);
    if (!agent) return;
    delete agent.promptMap[stageId];
  }

  updateAgentParticipantPersona(
    id: string,
    updatedPersona: Partial<AgentParticipantPersonaConfig>,
  ) {
    const agentIndex = this.agentParticipants.findIndex(
      (agent) => agent.persona.id === id,
    );
    if (agentIndex === -1) return;

    const oldAgent = this.agentParticipants[agentIndex];
    this.agentParticipants = [
      ...this.agentParticipants.slice(0, agentIndex),
      {
        persona: {...oldAgent.persona, ...updatedPersona},
        promptMap: oldAgent.promptMap,
      },
      ...this.agentParticipants.slice(agentIndex + 1),
    ];
  }

  // *********************************************************************** //
  // FIRESTORE                                                               //
  // *********************************************************************** //

  /** Create an experiment.
   * @rights Experimenter
   */
  async writeExperiment() {
    this.isWritingExperiment = true;

    // Update date modified
    this.experiment.metadata.dateModified = Timestamp.now();

    const response = await writeExperimentCallable(
      this.sp.firebaseService.functions,
      {
        collectionName: 'experiments',
        experimentTemplate: {
          id: '',
          experiment: this.experiment,
          stageConfigs: this.stages,
          agentMediators: this.agentMediators,
          agentParticipants: this.agentParticipants,
        },
      },
    );

    this.isWritingExperiment = false;
    return response;
  }

  /** Update an experiment.
   * @rights Experimenter who created the experiment
   */
  async updateExperiment() {
    this.isWritingExperiment = true;

    // Update date modified
    this.experiment.metadata.dateModified = Timestamp.now();

    const response = await updateExperimentCallable(
      this.sp.firebaseService.functions,
      {
        collectionName: 'experiments',
        experimentTemplate: {
          id: '',
          experiment: this.experiment,
          stageConfigs: this.stages,
          agentMediators: this.agentMediators,
          agentParticipants: this.agentParticipants,
        },
      },
    );

    this.isWritingExperiment = false;
    return response;
  }
}

import {computed, makeObservable, observable} from 'mobx';
import {
  collection,
  doc,
  getDocs,
  onSnapshot,
  Unsubscribe,
} from 'firebase/firestore';
import {FirebaseService} from './firebase.service';
import {Pages, RouterService} from './router.service';
