function getChips(numChips: number) {
  const redChip = {
    id: 'red',
    name: 'red',
    avatar: '🔴',
    canBuy: true,
    canSell: true,
    startingQuantity: N_INITIAL_RED_CHIPS,
    lowerValue: 0.1,
    upperValue: 1,
  };

  const blueChip = {
    id: 'blue',
    name: 'blue',
    avatar: '🔵',
    canBuy: true,
    canSell: true,
    startingQuantity: N_INITIAL_BLUE_CHIPS,
    lowerValue: 0.1,
    upperValue: 1,
  };

  const purpleChip = {
    id: 'purple',
    name: 'purple',
    avatar: '🟣',
    canBuy: true,
    canSell: true,
    startingQuantity: N_INITIAL_PURPLE_CHIPS,
    lowerValue: 0.1,
    upperValue: 1,
  };

  const greenChip = {
    id: 'green',
    name: 'green',
    avatar: '🟢',
    canBuy: true,
    canSell: true,
    startingQuantity: N_INITIAL_GREEN_CHIPS,
    lowerValue: 0.5,
    upperValue: 0.5,
  };

  const chips: ChipItem[] = [redChip];
  if (numChips > 2) {
    chips.push(blueChip);
  }
  if (numChips > 3) {
    chips.push(purpleChip);
  }

  // All games have the same-valuation green chip
  chips.push(greenChip);

  return chips;
}

